globalThis.__BQ = {"golgi":{"ilkokul":{"kolay":[{"q":"Bir hücreyi küçük bir fabrikaya benzetirsek, Golgi cisimciği bu fabrikada hangi işi yapan bölüme benzer?","steps":[{"t":"Golgi ne yapar?","a":"Paketleme ve gönderme","d":"Golgi cisimciği, hücrede üretilen maddeleri alır ve düzenler. Bu maddeleri küçük paketler hâline getirir. Sonra gerekli yerlere gönderilmek üzere hazırlar."},{"t":"Fabrikada karşılığı","a":"Paketleme ve sevkiyat bölümü","d":"Bir fabrikada ürünler kutulanıp gönderilir. Golgi de hücredeki maddeleri kutular gibi paketler. Bu yüzden paketleme ve gönderme bölümüne benzetilir."}],"ans":"Golgi cisimciği, ürünleri paketleyip gönderen paketleme ve sevkiyat bölümüne benzer."},{"q":"Golgi cisimciği hücrede yapılan maddeleri neden küçük keseciklere (kofullara) koyar?","steps":[{"t":"Kesecik nedir?","a":"Küçük zar torbası","d":"Kesecik, içinde madde taşıyan küçük bir zar torbasıdır. Golgi maddeleri bu torbaların içine koyar. Böylece maddeler dağılmadan bir arada durur."},{"t":"Neden kullanılır?","a":"Taşımak ve korumak için","d":"Maddeler torbanın içinde güvenle taşınır. Bu sayede madde hücre içinde dökülmeden ulaşacağı yere gider. Kesecikler taşıma ve koruma görevi yapar."}],"ans":"Maddeleri güvenle taşımak ve korumak için küçük keseciklerin içine koyar."},{"q":"Golgi cisimciği, hücrede daha önce başka bir organelde hazırlanan maddeleri alır. Bu durum Golgi'nin tek başına mı çalıştığını gösterir?","steps":[{"t":"Madde nereden gelir?","a":"Başka organelden","d":"Golgi'ye işlemek üzere maddeler başka bir organelden gelir. Yani Golgi maddeyi sıfırdan kendi yapmaz. Hazır gelen maddeyi alıp üzerinde çalışır."},{"t":"Birlikte çalışma","a":"Hayır, birlikte çalışır","d":"Golgi başka organellerden gelen maddeleri kullanır. Bu yüzden tek başına değil, diğer organellerle birlikte çalışır. Hücredeki organeller bir takım gibi iş bölümü yapar."}],"ans":"Hayır, Golgi başka organellerden gelen maddeleri işler; yani diğer organellerle birlikte çalışır."},{"q":"Tükürük gibi salgılar üreten hücrelerde Golgi cisimciği neden çok sayıda bulunur?","steps":[{"t":"Salgı nedir?","a":"Hücrenin dışarı verdiği madde","d":"Salgı, hücrenin ürettiği ve dışarı verdiği maddedir. Tükürük de bir salgıdır. Bu salgıların paketlenmesi gerekir."},{"t":"Golgi'nin görevi","a":"Salgıları paketler","d":"Golgi salgıları paketleyip dışarı gönderilmeye hazırlar. Çok salgı yapan hücrede bu iş çok olur. Bu yüzden bu hücrelerde Golgi sayısı fazladır."}],"ans":"Bol salgı paketlemesi gerektiği için salgı yapan hücrelerde Golgi sayısı fazladır."},{"q":"Golgi cisimciği bir zarla çevrili keseciklerden oluşur. Bu yapı Golgi'nin maddeleri ayrı tutmasına nasıl yardım eder?","steps":[{"t":"Zarlı yapı","a":"Bölmeleri ayırır","d":"Golgi üst üste dizilmiş zarlı keseciklerden oluşur. Zar, içerideki maddeyi dışarıdan ayırır. Böylece her kesecikte ayrı bir iş yapılabilir."},{"t":"Ayrı tutmanın yararı","a":"Karışmayı önler","d":"Maddeler ayrı keseciklerde tutulunca birbirine karışmaz. Bu sayede düzenli paketleme yapılır. Zarlı yapı bu düzeni sağlar."}],"ans":"Zarlı kesecikler maddeleri ayrı bölmelerde tutarak karışmalarını önler."}],"zor":[{"q":"Bir hücrede üretilen bir protein, önce işlenip sonra dışarı salgılanacaktır. Golgi bu yolculukta protein son hâline gelmeden önce mi sonra mı devreye girer?","steps":[{"t":"Önce ne olur?","a":"Protein üretilir","d":"Protein hücrede başka bir organelde üretilir. Bu hâliyle henüz tam hazır değildir. Üzerinde bazı değişiklikler yapılması gerekir."},{"t":"Golgi nerede girer?","a":"İşleme aşamasında","d":"Üretilen protein Golgi'ye gelir ve burada işlenir, düzenlenir. Sonra paketlenip gönderilir. Yani Golgi protein son hâline gelirken devreye girer."},{"t":"Sonuç","a":"Salgıdan önce","d":"Golgi proteini dışarı gönderilmeden önce hazırlar. İşleme ve paketleme bittikten sonra salgılanır. Demek ki Golgi salgılanmadan önce devreye girer."}],"ans":"Golgi, protein dışarı salgılanmadan önce onu işleyip paketleyerek son hâline getirir."},{"q":"Bir öğrenci \"Golgi maddeleri sadece paketler\" diyor. Golgi'nin paketlemeden başka bir işi daha olduğunu nasıl açıklarsın?","steps":[{"t":"Paketleme görevi","a":"Doğru ama eksik","d":"Golgi gerçekten maddeleri keseciklere paketler. Ama bu onun tek işi değildir. Paketlemeden önce maddeyi düzenler ve işler."},{"t":"İşleme görevi","a":"Maddeyi düzenler","d":"Golgi gelen maddeyi değiştirip kullanılabilir hâle getirir. Yani maddeyi işler. Bu, paketlemeden ayrı bir görevdir."},{"t":"Sonuç","a":"Hem işler hem paketler","d":"Golgi hem maddeleri işler hem de paketler. Bu yüzden sadece paketleyici demek eksiktir. Golgi'nin birden fazla görevi vardır."}],"ans":"Golgi sadece paketlemez; maddeleri işleyip düzenler de, yani birden fazla görevi vardır."},{"q":"Bir bezde salgı üretimi aniden çok artarsa, o hücrelerdeki Golgi sayısında nasıl bir değişiklik beklersin?","steps":[{"t":"Salgı artışı","a":"Daha çok paketleme","d":"Salgı arttıkça paketlenecek madde miktarı da artar. Her salgının paketlenmesi gerekir. Bu iş Golgi'ye düşer."},{"t":"Golgi yükü","a":"İş yükü artar","d":"Daha çok salgı, Golgi için daha çok iş demektir. Az sayıda Golgi bu işe yetmeyebilir. Bu durumda hücre daha fazla Golgi'ye ihtiyaç duyar."},{"t":"Beklenen değişiklik","a":"Golgi sayısı artar","d":"Artan iş yükünü karşılamak için Golgi sayısı artar. Böylece hücre tüm salgıyı paketleyebilir. Demek ki Golgi sayısında artış beklenir."}],"ans":"Salgı artınca paketleme işi de artacağı için hücrede Golgi sayısının artması beklenir."},{"q":"Golgi'nin oluşturduğu salgı kofulu hücre zarına doğru gider. Bu kofulun yolculuğunun sonunda ne olmasını beklersin?","steps":[{"t":"Kofulun içi","a":"Salgı maddesi var","d":"Salgı kofulu içinde dışarı verilecek madde bulunur. Golgi bu maddeyi paketleyip kofula koymuştur. Koful bu maddeyi taşır."},{"t":"Nereye gider?","a":"Hücre zarına","d":"Koful hücre zarına doğru hareket eder. Çünkü salgı hücre dışına verilecektir. Bunun için zara ulaşması gerekir."},{"t":"Sonuçta ne olur?","a":"Salgı dışarı verilir","d":"Koful zara ulaşınca içindeki madde dışarı boşaltılır. Böylece salgı hücre dışına çıkar. Yolculuğun sonunda salgılama gerçekleşir."}],"ans":"Koful hücre zarına ulaşır ve içindeki salgı maddesini hücre dışına boşaltır."},{"q":"Golgi cisimciği ile maddeyi üreten organel arasında kesecikler gidip gelir. Bu kesecikler olmasaydı hücrede ne gibi bir sorun çıkardı?","steps":[{"t":"Keseciğin işi","a":"Madde taşır","d":"Kesecikler maddeyi bir organelden diğerine taşır. Üretilen madde Golgi'ye kesecikle gelir. Yani kesecik bir taşıyıcıdır."},{"t":"Kesecik olmasaydı","a":"Madde ulaşamaz","d":"Kesecik olmazsa madde Golgi'ye taşınamaz. Üretilen madde olduğu yerde kalır. Golgi'ye hiçbir şey gelmez."},{"t":"Çıkacak sorun","a":"İşleme duraksar","d":"Golgi'ye madde gelmeyince işleme ve paketleme yapılamaz. Salgı hazırlanamaz. Böylece hücrenin salgı işi aksardı."}],"ans":"Kesecikler olmasaydı madde Golgi'ye taşınamaz, işleme ve paketleme yapılamaz, salgı işi aksardı."}]},"ortaokul":{"kolay":[{"q":"Golgi cisimciği, endoplazmik retikulumdan gelen proteinleri alır. Bu bilgi Golgi ile ER arasında nasıl bir ilişki olduğunu gösterir?","steps":[{"t":"ER'nin görevi","a":"Protein üretimi","d":"Endoplazmik retikulum hücrede protein üretiminde görev alır. Üretilen proteinler ER içinde toplanır. Daha sonra başka organele gönderilir."},{"t":"Golgi'ye aktarım","a":"Kesecikle taşınır","d":"ER'de hazırlanan proteinler keseciklerle Golgi'ye taşınır. Golgi bu proteinleri devralır. Böylece üretim ile işleme arasında bağlantı kurulur."},{"t":"İlişki","a":"Ardışık çalışma","d":"Önce ER protein üretir, sonra Golgi işler. Yani ikisi ardışık olarak çalışır. Bu, organellerin iş birliği yaptığını gösterir."}],"ans":"ER protein üretir, Golgi onu işler; ikisi ardışık çalışan, iş birliği yapan organellerdir."},{"q":"Golgi cisimciği yassı keseciklerin üst üste dizilmesiyle oluşur. Bu düzenli yapı Golgi'nin görevini nasıl kolaylaştırır?","steps":[{"t":"Yapı","a":"Üst üste kesecikler","d":"Golgi, yassı ve zarlı keseciklerin üst üste dizilmesiyle oluşur. Bu kesecikler birbirinden ayrıdır. Düzenli bir istif gibi görünür."},{"t":"Aşamalı işleme","a":"Her kesecik bir aşama","d":"Madde keseciklerden sırayla geçer. Her kesecikte ayrı bir işlem yapılabilir. Böylece işlem adım adım ilerler."},{"t":"Kolaylık","a":"Düzenli işleme","d":"Bu düzenli yapı sayesinde maddeler sırayla ve düzenli işlenir. İşlemler karışmaz. Golgi görevini daha verimli yapar."}],"ans":"Üst üste dizili kesecikler maddenin adım adım, düzenli işlenmesini sağlar ve görevi kolaylaştırır."},{"q":"Bir hücre çok az salgı yapıyor, başka bir hücre ise çok fazla salgı yapıyor. Golgi sayısı bakımından bu iki hücreyi nasıl karşılaştırırsın?","steps":[{"t":"Golgi ve salgı","a":"Golgi salgıyı paketler","d":"Golgi salgı maddelerini paketleyip gönderir. Salgı miktarı arttıkça paketleme işi de artar. Bu iş Golgi'ye düşer."},{"t":"Çok salgılayan hücre","a":"Çok Golgi","d":"Çok salgı yapan hücrede paketlenecek madde fazladır. Bu yüzden Golgi sayısı yüksektir. İş yükü Golgi miktarını belirler."},{"t":"Karşılaştırma","a":"Az salgıda az Golgi","d":"Az salgı yapan hücrede paketleme işi azdır. Bu yüzden daha az Golgi yeterlidir. Yani çok salgılayan hücrede Golgi sayısı daha fazladır."}],"ans":"Çok salgı yapan hücrede Golgi sayısı, az salgı yapana göre daha fazladır."},{"q":"Golgi cisimciğinin oluşturduğu yapılardan biri de lizozomdur. Bu bilgi Golgi'nin sadece salgıyla mı ilgili olduğunu gösterir?","steps":[{"t":"Golgi ve salgı","a":"Salgı paketler","d":"Golgi salgı maddelerini paketleyip dışarı göndermeye hazırlar. Bu, en bilinen görevidir. Ama tek görevi bu değildir."},{"t":"Lizozom oluşumu","a":"Golgi lizozom yapar","d":"Golgi, hücre içi sindirim yapan lizozomların oluşumunda da görev alır. Yani salgı dışında da iş yapar. Bu farklı bir görevdir."},{"t":"Sonuç","a":"Hayır, başka görevleri de var","d":"Golgi hem salgı paketler hem de lizozom oluşturur. Demek ki sadece salgıyla ilgili değildir. Birden fazla görevi vardır."}],"ans":"Hayır; Golgi salgı paketlemenin yanında lizozom oluşumunda da görev alır."},{"q":"Salgı bezi hücrelerinde Golgi cisimciğinin bol bulunması, bu hücrelerin hangi göreve uygun olduğunu düşündürür?","steps":[{"t":"Bol Golgi","a":"Çok paketleme","d":"Golgi sayısının fazla olması çok paketleme yapıldığını gösterir. Çünkü Golgi salgıları paketler. Bol Golgi, yoğun paketleme demektir."},{"t":"Salgı bezi görevi","a":"Salgı üretmek","d":"Salgı bezleri sürekli salgı üretir ve dışarı verir. Bu salgıların paketlenmesi gerekir. Bu yüzden bol Golgi gerekir."},{"t":"Çıkarım","a":"Salgılamaya uygun","d":"Bol Golgi, hücrenin yoğun salgı yapmaya uygun olduğunu gösterir. Yapı, göreve uyum sağlamıştır. Demek ki bu hücreler salgılamaya özelleşmiştir."}],"ans":"Bol Golgi bulunması, bu hücrelerin yoğun salgı üretmeye ve salgılamaya özelleştiğini gösterir."}],"zor":[{"q":"Bir hücrede önce ER'de protein üretiliyor, sonra Golgi'de işleniyor ve paketleniyor, en sonunda hücre dışına salgılanıyor. Bu sürecin doğru sırasını ve her organelin rolünü açıkla.","steps":[{"t":"1. Üretim","a":"ER protein yapar","d":"Süreç endoplazmik retikulumda başlar; burada protein üretilir. Üretilen protein keseciklere alınır. Bu kesecikler Golgi'ye doğru hareket eder."},{"t":"2. İşleme ve paketleme","a":"Golgi düzenler","d":"Protein Golgi'ye gelince burada işlenir ve düzenlenir. Ardından salgı kofulları hâlinde paketlenir. Golgi bu adımda son hazırlığı yapar."},{"t":"3. Salgılama","a":"Hücre dışına verilir","d":"Paketlenen salgı kofulu hücre zarına ulaşır. Zarla birleşip içeriğini dışarı boşaltır. Böylece protein hücre dışına salgılanır."}],"ans":"Önce ER protein üretir, sonra Golgi işleyip paketler, en son salgı kofulu zara ulaşıp içeriği dışarı verir."},{"q":"Bir bilim insanı, Golgi cisimciği bozulmuş bir hücrede salgı üretiminin durduğunu gözlemliyor. Bu gözlem Golgi'nin salgı için neden gerekli olduğunu nasıl gösterir?","steps":[{"t":"Golgi'nin rolü","a":"İşler ve paketler","d":"Golgi salgı maddelerini işler ve paketler. Bu işlem olmadan salgı dışarı gönderilemez. Golgi salgı yolunun önemli bir parçasıdır."},{"t":"Bozulunca ne olur","a":"Paketleme durur","d":"Golgi bozulunca işleme ve paketleme yapılamaz. Üretilen madde olduğu yerde kalır. Salgı kofulu oluşturulamaz."},{"t":"Gözlemin anlamı","a":"Golgi gerekli","d":"Salgı üretiminin durması, paketlemenin yapılamadığını gösterir. Bu da Golgi'nin salgı için zorunlu olduğunu kanıtlar. Golgi olmadan salgı tamamlanmaz."}],"ans":"Golgi bozulunca paketleme yapılamadığı için salgı durur; bu da Golgi'nin salgı için gerekli olduğunu gösterir."},{"q":"Bitki hücrelerinde Golgi, hücre bölünmesi sırasında yeni hücre duvarı yapımına katkı sağlayan madde paketlerini de oluşturur. Bu bilgi Golgi'nin görevleri hakkında ne söyler?","steps":[{"t":"Bilinen görev","a":"Salgı paketleme","d":"Golgi'nin yaygın bilinen görevi salgıları paketlemektir. Ancak bu tek görevi değildir. Farklı hücrelerde başka katkıları da vardır."},{"t":"Bitkideki ek görev","a":"Duvar maddesi","d":"Bitki hücresinde Golgi, hücre duvarı için gereken maddeleri paketler. Bu paketler bölünme sırasında kullanılır. Yeni duvarın yapımına katkı sağlar."},{"t":"Çıkarım","a":"Çok yönlü organel","d":"Golgi hem salgı hem de hücre duvarı yapımında rol alır. Demek ki görevi tek bir işle sınırlı değildir. Golgi çok yönlü bir organeldir."}],"ans":"Golgi yalnızca salgı paketlemez; bitkide hücre duvarı maddesi de hazırlar, yani çok yönlü görevleri vardır."},{"q":"İki hücreden biri sindirim enzimi salgılayan bir bez hücresi, diğeri ise kasta yer alan bir kas hücresidir. Golgi sayısı bakımından bu hücreleri karşılaştırıp nedenini açıkla.","steps":[{"t":"Bez hücresi","a":"Yoğun salgı","d":"Bez hücresi sürekli sindirim enzimi salgılar. Bu enzimlerin paketlenmesi gerekir. Bu da bol Golgi gerektirir."},{"t":"Kas hücresi","a":"Az salgı","d":"Kas hücresinin asıl görevi kasılmaktır, salgı yapmak değil. Bu yüzden paketleyeceği salgı azdır. Az Golgi yeterli olur."},{"t":"Karşılaştırma","a":"Bezde daha çok Golgi","d":"Salgı bezinde paketleme işi yoğundur, bu yüzden Golgi sayısı fazladır. Kas hücresinde ise Golgi daha azdır. Görev, Golgi miktarını belirler."}],"ans":"Yoğun salgı yaptığı için bez hücresinde Golgi sayısı, kas hücresine göre belirgin biçimde fazladır."},{"q":"Bir öğrenci Golgi cisimciğini ER'nin devamı gibi düşünüyor. ER ile Golgi'nin görevlerini karşılaştırarak bu iki organelin farklı olduğunu açıkla.","steps":[{"t":"ER'nin görevi","a":"Üretim","d":"Endoplazmik retikulum protein ve bazı maddelerin üretiminde görev alır. Üretim onun ana işidir. Burada ham ürün ortaya çıkar."},{"t":"Golgi'nin görevi","a":"İşleme ve paketleme","d":"Golgi üretilen maddeleri işler, düzenler ve paketler. Üretim yapmaz, hazır geleni hazırlar. Görevi sevkiyata hazırlamaktır."},{"t":"Fark","a":"Üretim ve hazırlık ayrı","d":"ER üretirken Golgi işleyip paketler. Yani görevleri birbirinden farklıdır. Birlikte çalışsalar da aynı organel değildirler."}],"ans":"ER maddeleri üretir, Golgi ise onları işleyip paketler; görevleri farklı olduğu için ayrı organellerdir."}]},"lise":{"kolay":[{"q":"Golgi aygıtının ER yüzüne yakın bölgesi (cis yüz) ile hücre zarına yakın bölgesi (trans yüz) farklı işlevler taşır. Bu kutuplu yapı, madde akışının yönü hakkında ne söyler?","steps":[{"t":"Cis yüz","a":"Madde giriş bölgesi","d":"Golgi'nin ER'ye bakan cis yüzü, ER'den gelen kesecikleri kabul eder. Maddeler buradan Golgi'ye girer. Bu yüz bir alım kapısı gibidir."},{"t":"Trans yüz","a":"Madde çıkış bölgesi","d":"Trans yüz hücre zarına yakındır ve işlenmiş ürünlerin paketlenip ayrıldığı bölgedir. Salgı kofulları buradan ayrılır. Bu yüz bir gönderim kapısı gibidir."},{"t":"Akışın yönü","a":"Cis'ten trans'a","d":"Maddeler cis yüzden girer, kesecikler arasında işlenir ve trans yüzden çıkar. Yani akış tek yönlüdür. Golgi'nin kutuplu yapısı bu düzenli yönü sağlar."}],"ans":"Kutuplu yapı, maddenin cis yüzden girip işlenerek trans yüzden çıktığı tek yönlü bir akış olduğunu gösterir."},{"q":"Golgi aygıtında proteinlere şeker grupları eklenerek glikoproteinler oluşturulur. Bu kimyasal değişikliğin proteinin işlevi için önemi nedir?","steps":[{"t":"Glikozilasyon","a":"Şeker eklenmesi","d":"Golgi'de proteinlere şeker zincirleri eklenir; bu olaya glikozilasyon denir. Böylece glikoprotein oluşur. Bu, proteinin yapısını değiştirir."},{"t":"İşlevsel etki","a":"Tanınma ve hedefleme","d":"Eklenen şeker grupları proteinin nereye gideceğini ve nasıl tanınacağını belirler. Hücre zarındaki tanıma işlevlerinde rol oynar. Bu da proteinin doğru çalışmasını sağlar."},{"t":"Önem","a":"İşlev kazandırır","d":"Şeker eklenmesi proteine son işlevsel kimliğini kazandırır. Bu olmadan protein doğru yere gidemez veya tanınamaz. Bu yüzden glikozilasyon kritik bir adımdır."}],"ans":"Şeker eklenmesi proteinin doğru hedeflenmesini ve tanınmasını sağlayarak ona işlevsel kimliğini kazandırır."},{"q":"Salgı yapan bez hücrelerinde (örneğin pankreasın enzim salgılayan hücreleri) hem ER hem Golgi gelişmiştir. Bu birliktelik salgı yolunun yapısı hakkında ne gösterir?","steps":[{"t":"ER gelişimi","a":"Yoğun üretim","d":"Gelişmiş ER, hücrede bol protein üretildiğini gösterir. Pankreas enzim hücreleri çok enzim üretir. Bu yüzden ER geniştir."},{"t":"Golgi gelişimi","a":"Yoğun paketleme","d":"Gelişmiş Golgi, üretilen enzimlerin yoğun şekilde işlenip paketlendiğini gösterir. Üretim arttıkça paketleme de artar. Bu yüzden Golgi de gelişmiştir."},{"t":"Yolun yapısı","a":"Üretim-paketleme zinciri","d":"ER ve Golgi'nin birlikte gelişmesi, salgı yolunun ardışık çalışan bir zincir olduğunu gösterir. Üretim ve paketleme aynı oranda artar. Yapı işleve uyum sağlamıştır."}],"ans":"ER ve Golgi'nin birlikte gelişmesi, salgı yolunun üretim ve paketlemeyi ardışık yürüten bir zincir olduğunu gösterir."},{"q":"Golgi aygıtından ayrılan kofullar; salgı kofulu, lizozom veya zarla birleşecek kesecik olabilir. Bu çeşitlilik Golgi'nin hücredeki konumu hakkında ne söyler?","steps":[{"t":"Çıkan ürün çeşitliliği","a":"Farklı hedefler","d":"Golgi'den çıkan kofullar farklı yerlere gider; bazıları dışarı salgılanır, bazıları lizozom olur, bazıları zara katılır. Yani çıkış ürünleri çeşitlidir. Her birinin ayrı bir görevi vardır."},{"t":"Dağıtım rolü","a":"Sıralama merkezi","d":"Golgi gelen maddeleri işleyip doğru hedefe göre ayırır ve gönderir. Bu, bir sıralama ve dağıtım işidir. Her ürün uygun adrese yönlendirilir."},{"t":"Konumu","a":"Dağıtım merkezi","d":"Bu çeşitlilik Golgi'nin hücrenin dağıtım merkezi olduğunu gösterir. Hem işleme hem yönlendirme yapar. Hücre içi madde trafiğinin merkezinde yer alır."}],"ans":"Çeşitli kofuller üretmesi, Golgi'nin maddeleri işleyip doğru hedeflere yönlendiren bir dağıtım merkezi olduğunu gösterir."},{"q":"Golgi aygıtının yassı keseciklerine \"sisterna\" denir ve bunlar birbirinden ayrı bölmelerdir. Bu bölmeli yapının enzimatik işlemler için sağladığı avantaj nedir?","steps":[{"t":"Sisterna yapısı","a":"Ayrı bölmeler","d":"Golgi yassı zarlı keseciklerden, yani sisternalardan oluşur. Her sisterna ayrı bir bölmedir. İçlerindeki ortam birbirinden farklı olabilir."},{"t":"Enzim ayrımı","a":"Farklı enzimler","d":"Her sisternada farklı enzimler bulunabilir. Madde sisternalar arası geçerken farklı işlemlerden geçer. Böylece işlemler birbirine karışmaz."},{"t":"Avantaj","a":"Aşamalı, düzenli işleme","d":"Bölmeli yapı, maddenin adım adım ve düzenli işlenmesini sağlar. Her aşama uygun enzimle yapılır. Bu da işlem doğruluğunu ve verimini artırır."}],"ans":"Ayrı sisternalar farklı enzimleri barındırarak maddenin aşamalı, düzenli ve birbirine karışmadan işlenmesini sağlar."},{"q":"Golgi aygıtı hücre içinde genellikle ER ile hücre zarı arasında konumlanır. Bu konumlanma, Golgi'nin görevine nasıl uygun düşer?","steps":[{"t":"ER ile ilişki","a":"Madde alımı","d":"Golgi ER'den madde alır. ER'ye yakın olması bu maddelerin kolay aktarılmasını sağlar. Kesecikler kısa mesafede taşınır."},{"t":"Zar ile ilişki","a":"Salgı gönderimi","d":"Golgi'den çıkan salgı kofulları hücre zarına gider. Zara yakın konum bu gönderimi kolaylaştırır. Salgı daha kısa yoldan ulaşır."},{"t":"Konumun uygunluğu","a":"Akışın ortasında","d":"Golgi, üretim yapan ER ile salgının çıkacağı zar arasında yer alır. Bu konum, madde akışının tam ortasıdır. Görevine en uygun yerde bulunur."}],"ans":"ER ile zar arasında konumlanması, Golgi'yi madde alımı ve salgı gönderimi akışının tam ortasına yerleştirerek görevine uygun düşer."},{"q":"Golgi aygıtı, ER'den gelen yanlış katlanmış proteinleri çoğunlukla işlemez ve bunlar geri gönderilir. Bu durum hücre için bir kalite kontrol anlamına gelir mi?","steps":[{"t":"Gelen protein","a":"Doğru katlanmalı","d":"ER'den Golgi'ye gelen proteinlerin doğru katlanmış olması gerekir. Yanlış katlanan proteinler işlevsizdir. Bunların salgılanması hücreye zarar verebilir."},{"t":"Geri gönderme","a":"Hatalı protein elenir","d":"Yanlış katlanmış proteinler Golgi yolunda ilerletilmez ve geri gönderilir. Böylece hatalı ürünler salgı yoluna girmez. Bu bir ayıklama işlemidir."},{"t":"Anlamı","a":"Kalite kontrol","d":"Sadece doğru proteinlerin ilerlemesi, bir kalite kontrol sürecidir. Hatalı ürünler elenir. Bu, hücrenin sağlıklı ürün üretmesini güvence altına alır."}],"ans":"Evet; yalnızca doğru katlanmış proteinlerin ilerletilmesi, salgı yolunda bir kalite kontrol mekanizması anlamına gelir."},{"q":"Bir mukus salgılayan hücre, salgıladığı mukusun kıvamını şeker zincirlerinin yoğunluğuyla ayarlar. Bu ayarlamada Golgi'nin rolü nedir?","steps":[{"t":"Mukus yapısı","a":"Şekerli protein","d":"Mukus, bol şeker zinciri taşıyan glikoproteinlerden oluşur. Şeker miktarı mukusun kıvamını etkiler. Bu yüzden şeker eklenmesi önemlidir."},{"t":"Golgi'nin işi","a":"Şeker ekler","d":"Proteinlere şeker zincirlerini ekleyen organel Golgi'dir. Golgi eklenen şeker miktarını işleyerek belirler. Böylece glikoproteinin yapısı şekillenir."},{"t":"Kıvam ayarı","a":"Golgi belirler","d":"Golgi'nin eklediği şeker yoğunluğu mukusun kıvamını ayarlar. Daha çok şeker daha farklı bir kıvam verir. Yani kıvam ayarında Golgi belirleyici rol oynar."}],"ans":"Golgi proteinlere şeker zincirleri ekleyerek glikoprotein yapısını ve böylece mukusun kıvamını belirler."},{"q":"Golgi aygıtı sürekli yenilenen, dinamik bir yapıdır; kesecikler bir yandan gelirken bir yandan ayrılır. Bu denge bozulursa Golgi'nin yapısına ne olabilir?","steps":[{"t":"Denge durumu","a":"Giriş = çıkış","d":"Golgi'ye cis yüzden kesecik gelirken trans yüzden kesecik ayrılır. Normalde giriş ve çıkış dengededir. Bu denge Golgi'nin yapısını korur."},{"t":"Denge bozulursa","a":"Birikme veya tükenme","d":"Giriş çıkıştan fazla olursa madde birikir ve Golgi şişer. Çıkış girişten fazla olursa madde tükenir ve Golgi küçülür. Her iki durumda yapı bozulur."},{"t":"Sonuç","a":"Yapı değişir","d":"Denge bozulunca Golgi'nin boyutu ve yapısı değişir. Bu da işlevini etkiler. Demek ki dinamik denge Golgi'nin sağlıklı yapısı için gereklidir."}],"ans":"Giriş-çıkış dengesi bozulursa Golgi ya madde birikiminden şişer ya da tükenmeden küçülür; her durumda yapısı bozulur."},{"q":"Golgi aygıtının ürettiği salgı kofulları, hücre dışına salınmak için hücre zarıyla birleşir. Bu birleşme aynı zamanda hücre zarına ne kazandırır?","steps":[{"t":"Kofulun zara ulaşması","a":"Zarla birleşir","d":"Salgı kofulu hücre zarına ulaşır ve zarla birleşir. İçindeki salgı dışarı boşaltılır. Bu olaya ekzositoz denir."},{"t":"Kofulun zarı","a":"Zara katılır","d":"Kofulun kendi zarı, hücre zarıyla birleşir ve onun parçası olur. Yani kofulun zarı hücre zarına eklenir. Hücre zarı bu sayede zar molekülü kazanır."},{"t":"Kazanım","a":"Zar yenilenmesi","d":"Bu birleşme hücre zarına yeni zar parçası katar. Böylece hücre zarı sürekli yenilenir. Salgılama hem madde gönderir hem zarı tamamlar."}],"ans":"Salgı kofulunun zarla birleşmesi, kofulun zarını hücre zarına katarak ona yeni zar molekülleri kazandırır ve zarı yeniler."},{"q":"Antikor üreten plazma hücreleri, ürettikleri antikorları kana salgılar. Bu hücrelerde Golgi'nin neden çok gelişmiş olması beklenir?","steps":[{"t":"Antikor","a":"Salgılanan protein","d":"Antikorlar bağışıklıkta görevli, salgılanan proteinlerdir. Plazma hücreleri çok sayıda antikor üretir. Bu antikorlar kana verilmek üzere hazırlanır."},{"t":"Golgi'nin rolü","a":"İşleme ve paketleme","d":"Üretilen antikorların işlenip paketlenmesi gerekir; bunu Golgi yapar. Çok antikor, çok paketleme demektir. Bu iş yükü Golgi'ye düşer."},{"t":"Beklenti","a":"Gelişmiş Golgi","d":"Yoğun antikor salgısı için Golgi'nin gelişmiş olması beklenir. Az Golgi bu işe yetmez. Bu yüzden plazma hücrelerinde Golgi belirgin biçimde gelişmiştir."}],"ans":"Yoğun antikor salgısını işleyip paketlemek için plazma hücrelerinde Golgi'nin çok gelişmiş olması beklenir."},{"q":"Golgi aygıtı bazı maddeleri sülfat veya fosfat grupları ekleyerek de değiştirir. Bu çeşitli kimyasal işlemler Golgi hakkında genel bir sonuç çıkarmaya yeter mi?","steps":[{"t":"Çeşitli işlemler","a":"Şeker, sülfat, fosfat","d":"Golgi proteinlere yalnızca şeker değil, sülfat ve fosfat grupları da ekleyebilir. Yani birden çok kimyasal işlem yapar. Her işlem maddeye farklı özellik kazandırır."},{"t":"İşlemlerin ortak amacı","a":"Maddeyi işlevsel kılar","d":"Bu işlemler maddeyi son işlevsel hâline getirir. Her ekleme maddenin görevine katkı sağlar. Golgi maddeyi kullanıma hazırlar."},{"t":"Genel sonuç","a":"İşleme merkezi","d":"Bu çeşitli kimyasal değişiklikler, Golgi'nin bir kimyasal işleme merkezi olduğunu gösterir. Sadece paketleyici değildir. Maddeleri çeşitli yollarla işler."}],"ans":"Evet; çeşitli kimyasal değişiklikler yapması, Golgi'nin maddeleri işlevsel kılan bir kimyasal işleme merkezi olduğunu gösterir."},{"q":"Golgi aygıtı bozulduğunda hem salgı üretimi hem lizozom oluşumu etkilenir. Bu çift etki Golgi'nin hücre içindeki önemini nasıl ortaya koyar?","steps":[{"t":"Salgıya etkisi","a":"Salgı durur","d":"Golgi bozulunca salgı maddeleri işlenip paketlenemez. Salgı kofulları oluşamaz. Böylece salgı üretimi durur."},{"t":"Lizozoma etkisi","a":"Lizozom oluşamaz","d":"Lizozomlar Golgi'nin katkısıyla oluşur. Golgi bozulunca lizozom yapımı da aksar. Hücre içi sindirim zorlaşır."},{"t":"Önem","a":"Birden çok yola etki","d":"Tek bir organelin bozulması birden çok hücresel yolu etkiler. Bu da Golgi'nin merkezî bir rol oynadığını gösterir. Golgi hücre için kritik bir organeldir."}],"ans":"Golgi bozulunca hem salgı hem lizozom oluşumu aksar; bu çift etki onun merkezî ve kritik bir organel olduğunu gösterir."},{"q":"Golgi aygıtının trans yüzünden ayrılan bir kofulun, salgı kofulu mu yoksa lizozom mu olacağı içeriğindeki belirteçlere göre belirlenir. Bu seçimin yanlış yapılması neye yol açabilir?","steps":[{"t":"Hedefleme belirteçleri","a":"İçeriğe göre ayrım","d":"Golgi, kofulun içindeki belirteçlere bakarak onu doğru hedefe yönlendirir. Belirteç, kofulun adresini gösterir gibidir. Doğru belirteç doğru hedef demektir."},{"t":"Yanlış yönlendirme","a":"Hatalı adres","d":"Belirteç yanlış okunursa koful yanlış yere gider. Örneğin sindirim enzimi salgı olarak dışarı verilebilir. Bu da yanlış yerde işlev görmesine yol açar."},{"t":"Sonuç","a":"Hücre işlevi bozulur","d":"Yanlış yönlendirilen enzimler veya maddeler zarar verebilir. Hücre içi sindirim aksayabilir veya istenmeyen salgı oluşur. Bu da hücre işleyişini bozar."}],"ans":"Yanlış yönlendirme, enzim veya maddelerin yanlış yere gitmesine ve hücre işleyişinin bozulmasına yol açabilir."},{"q":"Golgi cisimciğinin hücredeki temel görevi nedir?","steps":[{"t":"Görevi belirle","a":"İşleme, paketleme ve salgılama","d":"Golgi cisimciği, endoplazmik retikulumdan gelen protein ve lipitleri işler, etiketler ve paketler. Bu maddeleri kofullar (vezikül) içine alarak hücre içindeki hedefe ya da hücre dışına gönderir."},{"t":"Önemini kavra","a":"Hücrenin paketleme-sevkiyat merkezi","d":"Bu nedenle Golgi, hücrenin kargo ve paketleme merkezi gibi düşünülür. Tükürük, süt, hormon gibi salgı üreten bez hücrelerinde sayıca bol bulunur."}],"ans":"Maddeleri işleyip paketleyerek salgılamak"}],"zor":[{"q":"Pankreasın enzim salgılayan hücresinde bir sindirim enziminin ribozomda üretilmesinden hücre dışına salgılanmasına kadar geçen yolu, organellerin rollerini belirterek sıralı açıkla.","steps":[{"t":"1. Üretim","a":"Ribozom-ER","d":"Enzim, ER üzerindeki ribozomlarda üretilir ve granüllü ER'nin içine girer. Burada ön katlanma gerçekleşir. Ardından kesecikle Golgi'ye gönderilir."},{"t":"2. İşleme","a":"Golgi düzenler","d":"Golgi'nin cis yüzünden giren enzim, sisternalardan geçerken işlenir. Şeker eklenmesi gibi değişiklikler yapılır. Trans yüzde salgı kofulu hâlinde paketlenir."},{"t":"3. Olgunlaşma","a":"Salgı kofulu hazır","d":"Salgı kofulu hücre içinde olgunlaşır ve zara doğru hareket eder. İçinde işlenmiş enzim bulunur. Uygun sinyalle salgıya hazır hâle gelir."},{"t":"4. Salgılama","a":"Ekzositoz","d":"Koful hücre zarıyla birleşir ve içeriği dışarı boşaltılır; buna ekzositoz denir. Böylece enzim hücre dışına salgılanır. Yol tamamlanmış olur."}],"ans":"Enzim ribozom-ER'de üretilir, Golgi'de işlenip paketlenir, salgı kofulunda olgunlaşır ve ekzositozla dışarı salgılanır."},{"q":"Bir araştırmacı, Golgi enzimlerinin sisternalar boyunca yer değiştirdiğini ve \"sisterna olgunlaşması\" modeline göre keseciklerin cis'ten trans'a doğru kendisinin ilerlediğini öne sürüyor. Bu model madde akışını klasik görüşten nasıl farklı açıklar?","steps":[{"t":"Klasik görüş","a":"Sabit sisternalar","d":"Klasik görüşte sisternalar sabittir; madde kesecikler aracılığıyla bir sisternadan diğerine taşınır. Sisternalar yerinde durur. Yalnızca yük hareket eder."},{"t":"Olgunlaşma modeli","a":"Sisterna hareket eder","d":"Bu modelde sisternanın kendisi cis'ten trans'a doğru olgunlaşarak ilerler. Yük sisterna içinde kalır. Enzimler ise geriye doğru kesecikle taşınır."},{"t":"Fark","a":"Hareket eden farklı","d":"Klasik modelde yük taşınır, sisterna sabittir; olgunlaşma modelinde sisterna ilerler, enzimler geri taşınır. Yani hareket eden öge farklıdır. İki model akışı tersten kurgular."}],"ans":"Klasik modelde yük sabit sisternalar arasında taşınır; olgunlaşma modelinde sisternanın kendisi ilerler, enzimler ise geriye taşınır."},{"q":"Lizozom oluşumunda Golgi, sindirim enzimlerine mannoz-6-fosfat adı verilen bir belirteç ekler. Bu belirtecin eksik olması durumunda hücrede ne tür bir sorun ortaya çıkar?","steps":[{"t":"Belirtecin işlevi","a":"Lizozom adresi","d":"Mannoz-6-fosfat, sindirim enzimlerinin lizozoma yönlendirilmesini sağlayan bir adres etiketidir. Golgi bu etiketi enzimlere ekler. Etiket, enzimi doğru hedefe yönlendirir."},{"t":"Belirteç eksikse","a":"Yanlış yönlendirme","d":"Etiket eklenmezse enzimler lizozoma gidemez. Bunun yerine yanlışlıkla hücre dışına salgılanabilir. Lizozomda gerekli enzimler bulunmaz."},{"t":"Ortaya çıkan sorun","a":"Sindirim aksar","d":"Lizozomlar enzim alamayınca hücre içi sindirim yapamaz. Parçalanmamış maddeler hücrede birikir. Bu da hücresel işlevin bozulmasına yol açar."}],"ans":"Belirteç eksik olursa enzimler lizozoma yönlendirilemez, hücre içi sindirim aksar ve parçalanmamış maddeler birikir."},{"q":"Bir bitki hücresi bölünürken Golgi'den ayrılan kesecikler hücrenin ortasında birikerek orta lameli oluşturur. Bu süreçte Golgi'nin rolünü hayvan hücresindeki rolüyle karşılaştır.","steps":[{"t":"Bitkide rol","a":"Duvar maddesi sağlar","d":"Bölünen bitki hücresinde Golgi, hücre duvarı yapı maddelerini içeren kesecikler oluşturur. Bu kesecikler hücre ortasında toplanır. Orta lamel ve yeni duvar bunlardan kurulur."},{"t":"Hayvanda rol","a":"Salgı ve lizozom","d":"Hayvan hücresinde duvar yoktur; Golgi salgı kofulları ve lizozom oluşturur. Bölünmede duvar yapımı görevi yoktur. Görev salgı ve sindirimle sınırlıdır."},{"t":"Karşılaştırma","a":"Ortak işleyiş, farklı ürün","d":"Her iki hücrede de Golgi madde işleyip paketler, ama ürünler farklıdır. Bitkide duvar maddesi, hayvanda salgı/lizozom üretir. Temel işleyiş aynı, hücreye göre ürün değişir."}],"ans":"Golgi her iki hücrede madde işleyip paketler; ancak bitkide hücre duvarı/orta lamel maddesi, hayvanda ise salgı ve lizozom üretir."},{"q":"Granüllü ER, ribozomları nedeniyle bol protein üretir; Golgi ise bu proteinleri işler. ER ile Golgi'nin gelişmişlik düzeyleri arasında çoğunlukla bir paralellik görülür. Bu paralelliğin nedenini açıkla.","steps":[{"t":"ER üretimi","a":"Protein miktarı","d":"Granüllü ER ne kadar gelişmişse o kadar çok protein üretir. Üretim miktarı ER'nin büyüklüğüyle ilişkilidir. Bu da hücrenin protein ihtiyacına bağlıdır."},{"t":"Golgi yükü","a":"İşlenecek protein","d":"ER'de çok protein üretilince Golgi'ye gelen iş de artar. Golgi bu proteinleri işleyip paketlemek zorundadır. İş yükü ER üretimine bağlıdır."},{"t":"Paralelliğin nedeni","a":"Ortak iş yükü","d":"Üretim arttıkça işleme de artması gerekir; bu yüzden iki organel birlikte gelişir. Biri çok üretirken diğeri az işlerse darboğaz oluşur. Dengeli işleyiş için paralel gelişim gerekir."}],"ans":"ER'nin ürettiği protein miktarı Golgi'nin iş yükünü belirlediğinden, darboğaz olmaması için iki organel paralel olarak gelişir."},{"q":"Bir hücrede ekzositoz hızı çok artarsa, hücre zarının yüzey alanı sürekli artmamalı; ama gözlemler zar alanının dengede kaldığını gösterir. Golgi ve zar arasındaki bu dengeyi açıkla.","steps":[{"t":"Ekzositozun etkisi","a":"Zara zar eklenir","d":"Her ekzositozda salgı kofulunun zarı hücre zarına katılır. Bu, hücre zarının yüzey alanını artırır. Yoğun ekzositoz çok zar ekler."},{"t":"Dengeleyici süreç","a":"Endositoz","d":"Hücre, fazla zarı endositozla içeri alır ve geri çeker. Böylece dışarı eklenen zar dengelenir. Bu süreç zar fazlasını giderir."},{"t":"Genel denge","a":"Eklenen = geri alınan","d":"Ekzositozla eklenen zar, endositozla geri alınan zarla dengelenir. Bu yüzden zar alanı sabit kalır. Golgi madde gönderirken bu döngü zarı dengede tutar."}],"ans":"Ekzositozla eklenen zar endositozla geri alınarak dengelenir; bu döngü sayesinde yoğun salgıya rağmen zar alanı sabit kalır."},{"q":"Golgi aygıtındaki farklı sisternalarda (cis, orta, trans) farklı enzimler bulunması, proteinlere yapılan değişikliklerin belirli bir sırayla olmasını gerektirir. Bu sıralı işlemenin önemini açıkla.","steps":[{"t":"Enzim dağılımı","a":"Bölgeye özgü enzim","d":"Cis, orta ve trans sisternalarda farklı enzimler vardır. Her bölge belirli bir kimyasal işlemi yapar. Bu da bölgesel bir uzmanlaşma sağlar."},{"t":"İşlem sırası","a":"Adım adım değişim","d":"Protein sisternalardan sırayla geçerken her bölgede belirli bir değişikliğe uğrar. Yani işlemler belirli bir sırayla yapılır. Önceki işlem sonrakine zemin hazırlar."},{"t":"Önem","a":"Doğru son ürün","d":"Sıralı işleme, proteinin doğru biçimde olgunlaşmasını sağlar. Sıra bozulursa son ürün hatalı olur. Bu yüzden bölgesel ve sıralı işleme kritiktir."}],"ans":"Bölgelere özgü enzimler proteini belirli bir sırayla değiştirir; bu sıralı işleme doğru ve işlevsel son ürünün oluşması için gereklidir."},{"q":"Süt salgılayan meme bezi hücrelerinde hem süt proteinleri hem süt şekeri (laktoz) Golgi'de işlenip paketlenir. Bu durum Golgi'nin sadece proteinlerle mi ilgilendiğini gösterir?","steps":[{"t":"Protein işleme","a":"Bilinen görev","d":"Golgi proteinleri işleyip paketlemesiyle bilinir. Süt proteinleri de Golgi'de işlenir. Bu, beklenen bir görevdir."},{"t":"Laktoz oluşumu","a":"Şeker de işlenir","d":"Süt şekeri laktoz, Golgi'de gerçekleşen tepkimelerle oluşturulur ve paketlenir. Yani Golgi karbonhidratlarla da ilgilenir. Bu, protein dışı bir görevdir."},{"t":"Sonuç","a":"Sadece protein değil","d":"Golgi hem protein hem karbonhidrat işler ve paketler. Demek ki yalnızca proteinlerle ilgilenmez. Görevi çeşitli madde gruplarını kapsar."}],"ans":"Hayır; Golgi proteinlerin yanında karbonhidratları (örneğin laktozu) da işleyip paketler, yani çeşitli maddelerle ilgilenir."},{"q":"Bazı ilaçlar Golgi enzimlerini bloke ederek glikozilasyonu engeller. Böyle bir ilaç, hücre yüzeyindeki glikoproteinlerin tanınma işlevlerini nasıl etkiler?","steps":[{"t":"Glikozilasyon","a":"Şeker ekleme","d":"Golgi proteinlere şeker zincirleri ekleyerek glikoprotein oluşturur. Bu şekerler hücre yüzeyinde tanıma işlevi görür. İlaç bu eklemeyi engeller."},{"t":"İlacın etkisi","a":"Şeker eklenemez","d":"İlaç Golgi enzimlerini bloke edince proteinlere şeker eklenemez. Glikoproteinler eksik kalır. Yüzeydeki şeker yapıları oluşamaz."},{"t":"Tanınmaya etki","a":"Tanıma bozulur","d":"Şeker zincirleri olmadan hücre yüzeyindeki tanıma işlevleri aksar. Hücreler birbirini doğru tanıyamaz. Bu da hücreler arası iletişimi ve tanımayı bozar."}],"ans":"Glikozilasyon engellenince hücre yüzeyi glikoproteinleri eksik kalır ve hücrelerin birbirini tanıma işlevi bozulur."},{"q":"Golgi aygıtı, ER'den madde alırken cis yüzde COP keseciklerini kabul eder ve trans yüzde yeni kesecikler oluşturur. Bu sürekli kesecik trafiği Golgi'nin neden statik değil dinamik bir yapı olduğunu açıklar mı?","steps":[{"t":"Sürekli giriş","a":"Cis'te kesecik kabulü","d":"Golgi cis yüzünden sürekli kesecik alır; bu kesecikler ER'den gelir. Her gelen kesecik Golgi'ye yeni zar ve madde katar. Giriş kesintisiz sürer."},{"t":"Sürekli çıkış","a":"Trans'ta kesecik oluşumu","d":"Golgi trans yüzünde sürekli yeni kesecikler oluşturup gönderir. Her çıkan kesecik Golgi'den zar ve madde götürür. Çıkış da kesintisiz sürer."},{"t":"Dinamiklik","a":"Sürekli yenilenme","d":"Sürekli giriş ve çıkış Golgi'nin yapısını sürekli yeniler. Zar ve içerik durmadan değişir. Bu yüzden Golgi statik değil, dinamik bir yapıdır."}],"ans":"Evet; cis'ten sürekli kesecik girip trans'tan çıkması Golgi'nin zar ve içeriğini sürekli yeniler, bu da onu dinamik bir yapı yapar."},{"q":"Bir hücrede ER sağlıklı çalıştığı hâlde Golgi işlev görmüyorsa, salgılanması gereken proteinler hücrede birikir. Bu birikim hücre için neden tehlikeli olabilir?","steps":[{"t":"ER üretimi sürer","a":"Protein üretiliyor","d":"ER çalıştığı için proteinler üretilmeye devam eder. Bu proteinler Golgi'ye gönderilir. Ancak Golgi işlemediği için ilerleyemezler."},{"t":"Golgi durması","a":"İlerleme tıkanır","d":"Golgi işlev görmeyince proteinler işlenip paketlenemez. Salgı kofulu oluşamaz. Proteinler salgı yolunda tıkanır."},{"t":"Birikimin tehlikesi","a":"Hücre stresi","d":"İşlenmemiş proteinler hücrede birikerek yer kaplar ve hücreye stres verir. Aşırı birikim hücreye zarar verebilir, hatta ölümüne yol açabilir. Bu yüzden birikim tehlikelidir."}],"ans":"Golgi durunca üretilen proteinler işlenemeden birikir; bu birikim hücreye stres verir ve ileri durumda hücre ölümüne yol açabilir."},{"q":"Bir tek hücreli canlıda yoğun salgı dönemlerinde Golgi sayısının arttığı, salgının azaldığı dönemlerde ise azaldığı gözlemleniyor. Bu gözlem organel sayısı ile hücre ihtiyacı arasında nasıl bir ilişki olduğunu gösterir?","steps":[{"t":"Yoğun salgı dönemi","a":"Golgi artışı","d":"Salgı yoğunken paketleme işi de artar; bu da daha fazla Golgi gerektirir. Gözlemde Golgi sayısı artar. İhtiyaç organel sayısını yükseltir."},{"t":"Az salgı dönemi","a":"Golgi azalır","d":"Salgı azaldığında paketleme işi de azalır. Fazla Golgi gereksiz hâle gelir ve sayı düşer. İhtiyaç azalınca organel azalır."},{"t":"İlişki","a":"İhtiyaca göre ayarlanma","d":"Golgi sayısı hücrenin anlık ihtiyacına göre değişir. Organel sayısı sabit değildir, esnektir. Bu, hücrenin kaynaklarını verimli kullandığını gösterir."}],"ans":"Organel sayısı ihtiyaca göre ayarlanır; salgı arttıkça Golgi sayısı artar, azaldıkça düşer, bu da hücrenin kaynakları verimli kullandığını gösterir."},{"q":"Golgi aygıtının trans yüzünden çıkan kofulların bazıları hemen, bazıları ise yalnızca bir uyaran geldiğinde salgılanır. Bu iki salgılama biçimi arasındaki farkı ve hücreye sağladığı yararı açıkla.","steps":[{"t":"Sürekli salgılama","a":"Uyaransız çıkış","d":"Bazı kofuller oluşur oluşmaz doğrudan hücre zarına gidip içeriğini boşaltır. Bu sürekli (yapısal) salgılamadır. Bir uyarana gerek yoktur."},{"t":"Uyarılı salgılama","a":"Uyaranla çıkış","d":"Bazı kofuller hücre içinde bekler ve yalnızca bir uyaran geldiğinde salgılanır. Buna düzenlenmiş salgılama denir. Madde gerektiğinde hızlıca verilir."},{"t":"Yarar","a":"Esnek denetim","d":"İki biçim hücreye hem sürekli üretim hem de gerektiğinde anlık salgı imkânı verir. Hücre salgısını duruma göre ayarlar. Bu esneklik işlevsel bir avantaj sağlar."}],"ans":"Sürekli salgılama uyaransız ilerler, uyarılı salgılama beklenir ve uyaranla boşalır; bu ikisi hücreye salgıyı esnek biçimde denetleme yararı sağlar."},{"q":"Bir kıkırdak hücresi, hücreler arası boşluğu dolduran şekerli proteinleri (proteoglikanları) bol miktarda salgılar. Bu hücrede Golgi'nin hem bol hem de yoğun şeker ekleyen bir yapıda olması neyi gösterir?","steps":[{"t":"Proteoglikan yapısı","a":"Çok şekerli protein","d":"Proteoglikanlar, üzerinde bol şeker zinciri taşıyan büyük moleküllerdir. Kıkırdak bu maddeleri çok salgılar. Bu salgıların hazırlanması özel işlem gerektirir."},{"t":"Golgi'nin uyumu","a":"Bol ve şeker ekleyen","d":"Bol salgı için Golgi sayısı yüksek olmalıdır; yoğun şeker eklemek için de Golgi enzimleri etkin olmalıdır. Bu hücrede Golgi her ikisine de uygundur. Yapı göreve göre özelleşmiştir."},{"t":"Gösterdiği","a":"Yapı-işlev uyumu","d":"Golgi'nin bu özellikleri, hücrenin yoğun proteoglikan salgısına uyum sağladığını gösterir. Organel yapısı işleve göre biçimlenmiştir. Bu, yapı-işlev ilişkisinin bir örneğidir."}],"ans":"Bol ve yoğun şeker ekleyen Golgi, kıkırdak hücresinin yapısının proteoglikan salgısı işlevine özelleştiğini, yani yapı-işlev uyumunu gösterir."},{"q":"Golgi aygıtı hem ER'den madde alıp işler hem de lizozom oluşturur; lizozomlar ise hücre içi sindirim yapar. Bu zincirleme ilişki, organellerin hücrede nasıl bir bütün oluşturduğunu açıklar mı?","steps":[{"t":"ER-Golgi ilişkisi","a":"Üretim-işleme","d":"ER madde üretir, Golgi bunu alıp işler. Bu, ardışık bir iş birliğidir. İki organel bir üretim hattının parçası gibidir."},{"t":"Golgi-lizozom ilişkisi","a":"İşleme-sindirim","d":"Golgi sindirim enzimlerini paketleyip lizozom oluşturur. Lizozom bu enzimlerle hücre içi sindirim yapar. Böylece Golgi sindirim işlevine kaynak sağlar."},{"t":"Bütünlük","a":"Bağlantılı sistem","d":"ER, Golgi ve lizozom birbirine bağlı bir zincir oluşturur. Her organel diğerinin ürününü kullanır. Bu da hücrenin organellerden oluşan bütünleşik bir sistem olduğunu gösterir."}],"ans":"Evet; ER-Golgi-lizozom zinciri, organellerin birbirinin ürününü kullanarak hücrede bütünleşik bir sistem oluşturduğunu gösterir."}]}},"lizozomPerox":{"ilkokul":{"kolay":[{"q":"Lizozom, içinde sindirim yapan maddeler bulunduran bir kesecicktir. Lizozomu evdeki hangi araca benzetebiliriz?","steps":[{"t":"Lizozomun işi","a":"Parçalama","d":"Lizozom, hücre içindeki maddeleri parçalayıp küçültür. Yani bir tür sindirim yapar. Bunu içindeki özel maddelerle gerçekleştirir."},{"t":"Evdeki benzeri","a":"Mide gibi sindirir","d":"Mide nasıl besinleri sindiriyorsa lizozom da hücre içinde madde sindirir. Bu yüzden lizozom hücrenin minik midesi gibidir. Parçalama görevi onları benzer kılar."}],"ans":"Lizozom, madde sindirdiği için hücrenin minik midesine benzetilebilir."},{"q":"Lizozom hücreye giren bir zararlı maddeyi parçalayabilir. Bu durum lizozomun hücre için neden faydalı olduğunu gösterir mi?","steps":[{"t":"Lizozumun görevi","a":"Zararlıyı parçalar","d":"Lizozom hücreye giren zararlı maddeleri parçalar. Böylece bu maddeler etkisiz hâle gelir. Hücre korunmuş olur."},{"t":"Faydası","a":"Hücreyi korur","d":"Zararlıları yok ettiği için lizozom hücreyi korur. Bu da hücre için çok faydalıdır. Yani lizozom bir koruyucu görev yapar."}],"ans":"Evet; lizozom zararlı maddeleri parçalayarak hücreyi koruduğu için faydalıdır."},{"q":"Hücrede yaşlanmış ve işe yaramaz hâle gelen küçük parçalar oluşur. Lizozom bu parçalara ne yapar?","steps":[{"t":"Yaşlı parçalar","a":"İşe yaramaz","d":"Hücrede zamanla yıpranmış, işe yaramaz parçalar birikir. Bunlar yerinde kalırsa hücreyi kirletir. Temizlenmeleri gerekir."},{"t":"Lizozomun işi","a":"Parçalar","d":"Lizozom bu yaşlı parçaları sindirip parçalar. Böylece hücre temizlenir. Parçalanan maddeler yeniden kullanılabilir."}],"ans":"Lizozom yaşlanmış ve işe yaramaz parçaları sindirip parçalar, böylece hücreyi temizler."},{"q":"Peroksizom adlı kesecik, hücrede oluşan zararlı bir maddeyi parçalar. Bu görev peroksizomun hücreye nasıl yardım ettiğini gösterir?","steps":[{"t":"Zararlı madde","a":"Hücreye zarar verir","d":"Hücrede bazı işlemler sırasında zararlı bir madde oluşur. Bu madde hücreye zarar verebilir. Bu yüzden ortadan kaldırılması gerekir."},{"t":"Peroksizomun yardımı","a":"Zararlıyı temizler","d":"Peroksizom bu zararlı maddeyi parçalayıp zararsız hâle getirir. Böylece hücre korunur. Yani peroksizom bir temizleyici gibi yardım eder."}],"ans":"Peroksizom zararlı maddeyi parçalayıp zararsız hâle getirerek hücreyi korur."},{"q":"Lizozomun içinde sindirim yapan maddeler bir zarla çevrilidir. Bu zar neden gereklidir?","steps":[{"t":"İçindeki madde","a":"Sindirici madde","d":"Lizozomun içinde madde parçalayan güçlü maddeler bulunur. Bu maddeler her şeyi sindirebilir. Bu yüzden kontrol altında tutulmalıdır."},{"t":"Zarın görevi","a":"Etrafı korur","d":"Zar, bu sindirici maddelerin dışarı çıkmasını engeller. Böylece hücrenin sağlam parçaları zarar görmez. Zar bir koruyucu duvar gibidir."}],"ans":"Zar, sindirici maddelerin dışarı çıkıp hücreye zarar vermesini engellediği için gereklidir."}],"zor":[{"q":"Bir hücrede lizozomlar çalışmazsa, yaşlanmış parçalar ve zararlı maddeler hücrede ne olur? Sonucu açıkla.","steps":[{"t":"Lizozomun görevi","a":"Temizlik ve sindirim","d":"Lizozom yaşlı parçaları ve zararlı maddeleri sindirip temizler. Bu sayede hücre temiz kalır. Bu görev sürekli yapılır."},{"t":"Çalışmazsa","a":"Birikme olur","d":"Lizozom çalışmazsa parçalanması gereken maddeler parçalanamaz. Bunlar hücrede birikmeye başlar. Temizlik yapılamaz."},{"t":"Sonuç","a":"Hücre kirlenir","d":"Biriken maddeler hücreyi kirletir ve işleyişini bozar. Hücre düzgün çalışamaz. Bu da hücreye zarar verir."}],"ans":"Lizozomlar çalışmazsa yaşlı parçalar ve zararlılar parçalanamaz, hücrede birikir ve hücrenin işleyişi bozulur."},{"q":"Bir öğrenci \"Lizozom ve peroksizom aynı işi yapar\" diyor. Bu iki keseciğin görevlerinin farklı olduğunu nasıl açıklarsın?","steps":[{"t":"Lizozomun işi","a":"Madde sindirir","d":"Lizozom yaşlı parçaları, zararlı maddeleri ve yabancı cisimleri sindirip parçalar. Onun işi hücre içi sindirimdir. Geniş bir parçalama görevi yapar."},{"t":"Peroksizomun işi","a":"Zararlı maddeyi parçalar","d":"Peroksizom özellikle hücrede oluşan zararlı bir maddeyi parçalar. Onun görevi daha özeldir. Sindirim değil, zararsızlaştırma yapar."},{"t":"Fark","a":"Görevleri farklı","d":"Lizozom geniş sindirim yaparken peroksizom belirli zararlı maddeyi temizler. Yani görevleri aynı değildir. İkisi farklı işler yapar."}],"ans":"Lizozom hücre içi sindirim yapar, peroksizom ise belirli zararlı maddeleri parçalar; görevleri farklıdır."},{"q":"Bir hücre, içine aldığı bir besin parçasını lizozomla birleştiriyor. Bu birleşmeden sonra besin parçasına ne olmasını beklersin?","steps":[{"t":"Besin alınır","a":"İçeri girer","d":"Hücre dışarıdan bir besin parçasını içine alır. Bu parça henüz büyüktür ve doğrudan kullanılamaz. Önce parçalanması gerekir."},{"t":"Lizozomla birleşme","a":"Sindirim başlar","d":"Besin parçası lizozomla birleşince sindirim başlar. Lizozomun maddeleri besini parçalar. Büyük parça küçülmeye başlar."},{"t":"Sonuç","a":"Parçalanır","d":"Besin küçük parçalara ayrılır ve hücre tarafından kullanılabilir hâle gelir. Yani sindirilmiş olur. Hücre bu parçaları kullanabilir."}],"ans":"Besin parçası lizozomla birleşince sindirilir ve hücrenin kullanabileceği küçük parçalara ayrılır."},{"q":"Peroksizom, parçaladığı zararlı maddeyi su gibi zararsız maddelere dönüştürür. Bu dönüşüm hücre için neden önemlidir?","steps":[{"t":"Zararlı madde","a":"Tehlikeli","d":"Peroksizomun parçaladığı madde hücreye zarar verebilen tehlikeli bir maddedir. Birikirse hücreyi bozar. Bu yüzden tehlikelidir."},{"t":"Dönüşüm","a":"Zararsız hâle gelir","d":"Peroksizom bu maddeyi su gibi zararsız maddelere çevirir. Artık hücreye zarar veremez. Tehlike ortadan kalkar."},{"t":"Önemi","a":"Hücreyi korur","d":"Bu dönüşüm sayesinde hücre zarar görmekten kurtulur. Tehlikeli madde temizlenmiş olur. Bu yüzden dönüşüm hücre için çok önemlidir."}],"ans":"Zararlı maddeyi su gibi zararsız maddelere çevirmesi hücreyi zarardan koruduğu için önemlidir."},{"q":"Sürekli zararlı madde oluşturan, çok çalışan bir hücrede peroksizom sayısı nasıl olur? Nedenini açıkla.","steps":[{"t":"Çok çalışan hücre","a":"Çok zararlı madde","d":"Çok çalışan bir hücrede işlemler sırasında bol zararlı madde oluşur. Bu maddenin temizlenmesi gerekir. Temizlik işi artar."},{"t":"Peroksizomun görevi","a":"Zararlıyı temizler","d":"Peroksizom zararlı maddeleri parçalar. Zararlı madde arttıkça temizlik işi de artar. Bu iş peroksizomlara düşer."},{"t":"Sonuç","a":"Peroksizom çoğalır","d":"Daha çok temizlik için daha çok peroksizom gerekir. Bu yüzden bu hücrede peroksizom sayısı yüksek olur. İhtiyaç sayıyı artırır."}],"ans":"Çok zararlı madde oluştuğu için temizlik işi artar; bu yüzden bu hücrede peroksizom sayısı yüksek olur."}]},"ortaokul":{"kolay":[{"q":"Lizozom, içinde sindirim enzimleri taşıyan zarlı bir kofulcuktur. Enzimlerin zarla çevrili olması hücre için neden gereklidir?","steps":[{"t":"Sindirim enzimi","a":"Madde parçalar","d":"Lizozomun içinde madde parçalayan sindirim enzimleri bulunur. Bu enzimler güçlüdür ve birçok maddeyi parçalayabilir. Kontrolsüz kalırlarsa zarar verebilir."},{"t":"Zarın görevi","a":"Enzimi sınırlar","d":"Zar, enzimlerin yalnızca lizozom içinde kalmasını sağlar. Böylece enzimler dışarı çıkıp hücreyi sindiremez. Zar bir sınır gibi davranır."},{"t":"Gereklilik","a":"Hücreyi korur","d":"Zar olmadan enzimler hücrenin kendi parçalarına zarar verebilir. Bu yüzden zar koruma sağlar. Zar, hücrenin güvenliği için gereklidir."}],"ans":"Zar, sindirim enzimlerini lizozom içinde tutarak hücrenin kendi yapılarına zarar vermesini önlediği için gereklidir."},{"q":"Lizozomun hücre içi sindirim yapması, onun beslenme ve temizlikteki rolü hakkında ne söyler?","steps":[{"t":"Sindirim görevi","a":"Maddeyi küçültür","d":"Lizozom büyük maddeleri sindirip küçük parçalara ayırır. Bu parçalar hücre tarafından kullanılabilir. Sindirim, maddeyi kullanılabilir kılar."},{"t":"Beslenmedeki rol","a":"Besini hazırlar","d":"Lizozom alınan besinleri sindirerek hücrenin kullanımına sunar. Böylece hücre beslenir. Bu, beslenmedeki rolüdür."},{"t":"Temizlikteki rol","a":"Atığı parçalar","d":"Lizozom yaşlı ve atık maddeleri de parçalar. Böylece hücre temizlenir. Bu da temizlikteki rolüdür."}],"ans":"Lizozom hem besinleri sindirerek beslenmeye katkı sağlar hem de atıkları parçalayarak hücreyi temizler."},{"q":"Peroksizom, hidrojen peroksit adlı zararlı maddeyi katalaz enzimiyle parçalar. Bu bilgi peroksizomun görevini nasıl özetler?","steps":[{"t":"Hidrojen peroksit","a":"Zararlı madde","d":"Hücrede oluşan hidrojen peroksit hücreye zarar verebilen bir maddedir. Birikmesi tehlikelidir. Bu yüzden parçalanması gerekir."},{"t":"Katalaz enzimi","a":"Parçalayıcı enzim","d":"Peroksizom içindeki katalaz enzimi hidrojen peroksiti parçalar. Bu enzim peroksizomda bulunur. Onun sayesinde zararlı madde yok edilir."},{"t":"Görev özeti","a":"Zararsızlaştırma","d":"Peroksizom, katalaz enzimiyle hidrojen peroksiti zararsız hâle getirir. Yani hücreyi zararlı maddeden korur. Görevi bir tür zararsızlaştırmadır."}],"ans":"Peroksizom, katalaz enzimiyle zararlı hidrojen peroksiti parçalayarak hücreyi koruyan bir organeldir."},{"q":"Karaciğer hücrelerinde peroksizom sayısının fazla olması, bu hücrelerin görevi hakkında ne düşündürür?","steps":[{"t":"Karaciğerin görevi","a":"Zararlıları işler","d":"Karaciğer, vücuttaki birçok zararlı maddeyi işleyen bir organdır. Bu işlemler sırasında zararlı maddeler oluşur veya işlenir. Bu yüzden temizlik işi yoğundur."},{"t":"Peroksizom sayısı","a":"Çok temizlik","d":"Peroksizom zararlı maddeleri parçalar. Karaciğerde bu iş çok olduğu için peroksizom sayısı fazladır. Bol peroksizom yoğun temizlik demektir."},{"t":"Çıkarım","a":"Zararsızlaştırmaya uygun","d":"Bol peroksizom, karaciğer hücrelerinin zararlı maddeleri parçalama görevine uygun olduğunu düşündürür. Yapı göreve uymuştur. Bu hücreler zararsızlaştırmaya özelleşmiştir."}],"ans":"Bol peroksizom, karaciğer hücrelerinin zararlı maddeleri parçalayıp zararsızlaştırma görevine özelleştiğini düşündürür."},{"q":"Lizozom Golgi cisimciği tarafından oluşturulur. Bu bilgi lizozom ile Golgi arasında nasıl bir bağlantı olduğunu gösterir?","steps":[{"t":"Golgi'nin görevi","a":"Paketleme","d":"Golgi maddeleri işleyip paketler. Sindirim enzimlerini de paketler. Bu enzimler bir kofulun içine konur."},{"t":"Lizozom oluşumu","a":"Golgi'den ayrılır","d":"Golgi, sindirim enzimleriyle dolu kofulu oluşturur ve bu koful lizozoma dönüşür. Yani lizozom Golgi'den köken alır. Golgi onun kaynağıdır."},{"t":"Bağlantı","a":"Kaynak-ürün ilişkisi","d":"Golgi lizozomu oluşturduğu için aralarında kaynak-ürün ilişkisi vardır. Golgi olmadan lizozom oluşamaz. İki yapı birbirine bağlıdır."}],"ans":"Lizozomu Golgi oluşturur; yani aralarında Golgi'nin kaynak, lizozomun ürün olduğu bir bağlantı vardır."}],"zor":[{"q":"Bir hücre dışarıdan aldığı bir bakteriyi yok etmek istiyor. Lizozomun bu süreçte üstlendiği rolü adım adım açıkla.","steps":[{"t":"Bakteri alınır","a":"Hücre içine girer","d":"Hücre, zararlı bakteriyi bir kofulla içine alır. Bakteri henüz canlı ve zararlıdır. Yok edilmesi gerekir."},{"t":"Lizozomla birleşme","a":"Enzimler boşalır","d":"Bakteriyi taşıyan koful lizozomla birleşir. Lizozomdaki sindirim enzimleri bakterinin üzerine boşalır. Parçalama başlar."},{"t":"Bakteri parçalanır","a":"Yok edilir","d":"Enzimler bakteriyi parçalara ayırır ve etkisiz hâle getirir. Böylece bakteri yok edilir. Hücre tehlikeden kurtulur."}],"ans":"Lizozom, bakteriyi taşıyan kofulla birleşip sindirim enzimlerini boşaltır ve bakteriyi parçalayarak yok eder."},{"q":"Bir öğrenci \"Peroksizom sadece bir enzim taşır\" diyor. Peroksizomun hidrojen peroksiti parçalamasının yanında yağları yıkmada da görev aldığını ekleyerek bu görüşü düzelt.","steps":[{"t":"Bilinen görev","a":"Hidrojen peroksit parçalama","d":"Peroksizom katalaz enzimiyle hidrojen peroksiti parçalar. Bu, en bilinen görevidir. Ama tek görevi değildir."},{"t":"Ek görev","a":"Yağ yıkımı","d":"Peroksizom, yağ asitlerinin yıkılmasında da görev alır. Yani yağların parçalanmasına katkı sağlar. Bu ayrı bir görevdir."},{"t":"Düzeltme","a":"Birden çok görev","d":"Peroksizom hem hidrojen peroksiti parçalar hem de yağ yıkar. Demek ki tek bir işi yoktur. Birden fazla görevi vardır."}],"ans":"Peroksizom yalnızca hidrojen peroksiti parçalamaz; yağ asitlerinin yıkımında da görev alır, yani birden çok görevi vardır."},{"q":"Lizozom enzimleri yanlışlıkla hücre içine dağılırsa hücreye ne olabilir? Bu durum lizozom zarının önemini nasıl gösterir?","steps":[{"t":"Enzimlerin gücü","a":"Madde parçalar","d":"Lizozom enzimleri hücredeki birçok maddeyi parçalayabilir. Çok güçlüdürler. Normalde sadece lizozom içinde çalışırlar."},{"t":"Dağılırsa","a":"Hücre sindirilir","d":"Enzimler hücre içine dağılırsa hücrenin kendi yapılarını parçalamaya başlar. Hücre kendi kendini sindirir. Bu hücreye büyük zarar verir."},{"t":"Zarın önemi","a":"Enzimleri tutar","d":"Lizozom zarı enzimleri içeride tutarak bu zararı önler. Zar olmazsa enzimler kontrolsüz kalır. Bu da zarın hayati önemini gösterir."}],"ans":"Enzimler dağılırsa hücre kendi kendini sindirir; bu da lizozom zarının enzimleri güvenle tutmasının hayati önemini gösterir."},{"q":"Karaciğerde alkol gibi zararlı maddeler işlenirken hidrojen peroksit oluşur. Karaciğer hücrelerinde peroksizomun bol bulunmasını bu bilgiyle açıkla.","steps":[{"t":"Zararlı madde işleme","a":"Hidrojen peroksit oluşur","d":"Karaciğer alkol gibi zararlı maddeleri işler. Bu işlemler sırasında hidrojen peroksit gibi zararlı yan ürünler oluşur. Bu yan ürünlerin temizlenmesi gerekir."},{"t":"Peroksizomun görevi","a":"Hidrojen peroksiti parçalar","d":"Peroksizom hidrojen peroksiti katalaz enzimiyle parçalar. Karaciğerde bol hidrojen peroksit oluştuğu için temizlik işi çoktur. Bu iş peroksizomlara düşer."},{"t":"Bol bulunma nedeni","a":"Yoğun temizlik","d":"Çok zararlı yan ürün için çok peroksizom gerekir. Bu yüzden karaciğer hücrelerinde peroksizom boldur. İhtiyaç sayıyı artırmıştır."}],"ans":"Karaciğerde zararlı madde işlenirken bol hidrojen peroksit oluştuğu için, bunu parçalayacak peroksizomlar bol bulunur."},{"q":"Bir hücrede hem lizozom hem peroksizom bulunur ve ikisi de parçalama yapar. Bu iki organelin parçaladığı maddeler ve yöntemleri bakımından farkını açıkla.","steps":[{"t":"Lizozomun işi","a":"Geniş sindirim","d":"Lizozom büyük maddeleri, yaşlı organelleri ve yabancı cisimleri sindirim enzimleriyle parçalar. Geniş bir sindirim yapar. Çeşitli maddelere etki eder."},{"t":"Peroksizomun işi","a":"Özel parçalama","d":"Peroksizom özellikle hidrojen peroksiti katalaz enzimiyle parçalar ve yağ asitlerini yıkar. Görevi daha özeldir. Belirli maddelere odaklanır."},{"t":"Fark","a":"Madde ve yöntem farklı","d":"Lizozom geniş kapsamlı sindirim yaparken peroksizom belirli zararlı maddeleri ve yağları işler. Parçaladıkları maddeler ve enzimleri farklıdır. İkisi farklı işlevlere sahiptir."}],"ans":"Lizozom çeşitli maddeleri sindirim enzimleriyle geniş biçimde parçalar; peroksizom ise katalazla hidrojen peroksiti parçalar ve yağ asitlerini yıkar."}]},"lise":{"kolay":[{"q":"Lizozom enzimleri en iyi asidik ortamda çalışır ve lizozom içi sitoplazmadan daha asidiktir. Bu özellik hücre için bir güvenlik sağlar mı?","steps":[{"t":"Asidik ortam","a":"Enzimler için uygun","d":"Lizozom içi sitoplazmaya göre daha asidiktir ve enzimler bu ortamda etkin çalışır. Yani enzimler asidik ortama uyumludur. Bu ortam içeride sağlanır."},{"t":"Sitoplazma ortamı","a":"Daha az asidik","d":"Sitoplazma lizozom içinden daha az asidiktir; yani daha nötr ortamdır. Enzimler bu ortamda iyi çalışmaz. Etkinlikleri düşer."},{"t":"Güvenlik","a":"Kazara zararı azaltır","d":"Enzimler kazara sitoplazmaya sızsa bile orada iyi çalışamaz çünkü ortam yeterince asidik değildir. Bu, hücre için ek bir güvenlik sağlar. Zar dışında ikinci bir koruma katmanıdır."}],"ans":"Evet; enzimler yalnızca asidik lizozom içinde etkin olduğu için sitoplazmaya sızsalar bile zarar veremez, bu ek bir güvenlik sağlar."},{"q":"Peroksizomdaki katalaz enzimi hidrojen peroksiti suya ve oksijene parçalar. Bu tepkimenin hücre için sağladığı yarar nedir?","steps":[{"t":"Hidrojen peroksit","a":"Zararlı yan ürün","d":"Hidrojen peroksit, hücredeki bazı tepkimelerde oluşan zararlı bir yan üründür. Birikirse hücre yapılarına zarar verir. Bu yüzden uzaklaştırılması gerekir."},{"t":"Katalazın etkisi","a":"Zararsız ürünler","d":"Katalaz enzimi hidrojen peroksiti su ve oksijene ayırır. Bu ürünler hücreye zarar vermez. Tehlikeli madde zararsız hâle gelir."},{"t":"Yarar","a":"Hücreyi korur","d":"Bu tepkime sayesinde hücre zararlı hidrojen peroksitin etkilerinden korunur. Hücre yapıları zarar görmez. Böylece hücre sağlıklı kalır."}],"ans":"Katalaz, zararlı hidrojen peroksiti zararsız su ve oksijene çevirerek hücreyi oksidatif hasardan korur."},{"q":"Hücrenin yaşlanmış veya hasarlı organellerini parçalayıp yapı taşlarını geri kazandırması \"otofaji\" olarak adlandırılır. Bu süreçte lizozomun rolü nedir?","steps":[{"t":"Otofaji","a":"Kendini sindirme","d":"Otofaji, hücrenin kendi yaşlı veya hasarlı organellerini parçalama sürecidir. Bu organeller bir zarla sarılır. Sonra parçalanmak üzere taşınır."},{"t":"Lizozomun rolü","a":"Parçalama yeri","d":"Sarılan organel lizozomla birleşir ve lizozom enzimleriyle parçalanır. Yani sindirim lizozomda gerçekleşir. Lizozom parçalama merkezidir."},{"t":"Geri kazanım","a":"Yapı taşları","d":"Parçalanan organelin yapı taşları hücreye geri verilir ve yeniden kullanılır. Böylece kaynak israf edilmez. Lizozom bu geri dönüşümü sağlar."}],"ans":"Otofajide lizozom, zara sarılı yaşlı organeli enzimleriyle parçalar ve yapı taşlarını yeniden kullanıma kazandırır."},{"q":"Peroksizomlar yağ asitlerinin yıkımına katkı sağlar ve bu süreçte hidrojen peroksit oluşur. Aynı organelde hem yağ yıkımı hem hidrojen peroksit parçalamasının olması neyi gösterir?","steps":[{"t":"Yağ yıkımı","a":"Hidrojen peroksit üretir","d":"Peroksizomda yağ asitleri yıkılırken hidrojen peroksit açığa çıkar. Bu zararlı bir yan üründür. Aynı organelde oluşur."},{"t":"Katalaz devrede","a":"Hidrojen peroksiti parçalar","d":"Peroksizomdaki katalaz, oluşan hidrojen peroksiti hemen parçalar. Böylece zararlı madde birikmez. Üretildiği yerde temizlenir."},{"t":"Gösterdiği","a":"Bütünleşik düzen","d":"Aynı organelde zararlı yan ürünün hem üretilip hem temizlenmesi, işlerin bütünleşik biçimde düzenlendiğini gösterir. Üretim ve temizlik aynı yerde olur. Bu da verimli ve güvenli bir düzendir."}],"ans":"Zararlı yan ürünün üretildiği yerde hemen temizlenmesi, peroksizomda işlevlerin bütünleşik ve güvenli biçimde düzenlendiğini gösterir."},{"q":"Lizozomlar Golgi aygıtının trans yüzünden, sindirim enzimleriyle paketlenmiş kofuller olarak ayrılır. Bu köken bilgisi lizozom ile salgı yolu arasında nasıl bir ilişki kurar?","steps":[{"t":"Enzim üretimi","a":"ER-Golgi yolu","d":"Lizozom enzimleri ER'de üretilir ve Golgi'de işlenip paketlenir. Yani salgı yolundan geçerler. Üretim ve işleme aynı yolu kullanır."},{"t":"Lizozom ayrımı","a":"Trans yüzden çıkar","d":"Enzimler Golgi'nin trans yüzünde paketlenir ve lizozom olarak ayrılır. Bu, salgı kofullarının da çıktığı bölgedir. Lizozom da bu yoldan oluşur."},{"t":"İlişki","a":"Aynı yolun parçası","d":"Lizozomlar salgı yolunun bir ürünüdür; salgı kofullarıyla aynı sistemden köken alır. Yani lizozom oluşumu salgı yoluyla bütünleşiktir. İkisi ortak bir sisteme aittir."}],"ans":"Lizozom enzimleri ER-Golgi salgı yolundan geçip trans yüzde paketlenir; bu da lizozomun salgı yoluyla bütünleşik olduğunu gösterir."},{"q":"Lizozom içeren ve yoğun hücre içi sindirim yapan akyuvarlarda (örneğin fagosit hücrelerde) bol lizozom bulunması neyi gösterir?","steps":[{"t":"Fagosit görevi","a":"Yabancı yutma","d":"Fagosit akyuvarlar vücuda giren bakteri ve yabancı maddeleri yutar. Bu maddelerin yok edilmesi gerekir. Yok etme hücre içinde olur."},{"t":"Lizozomun rolü","a":"Yutulanı parçalar","d":"Yutulan yabancı maddeler lizozomlarla birleşip parçalanır. Çok yutma, çok parçalama demektir. Bu iş lizozomlara düşer."},{"t":"Bol lizozom","a":"Yoğun sindirime özelleşme","d":"Bol lizozom, bu hücrelerin yoğun hücre içi sindirim yaptığını gösterir. Yapı göreve uygundur. Yani fagositler savunma amaçlı sindirime özelleşmiştir."}],"ans":"Bol lizozom, fagosit akyuvarların yuttukları yabancı maddeleri yoğun biçimde sindirmeye, yani savunma görevine özelleştiğini gösterir."},{"q":"Hidrojen peroksit hem zararlı bir oksitleyici hem de bazı durumlarda hücrenin savunmada kullandığı bir maddedir. Peroksizomun katalaz dengesi bu durumda neden önemlidir?","steps":[{"t":"Hidrojen peroksitin ikili yönü","a":"Hem zararlı hem yararlı","d":"Hidrojen peroksit fazla olduğunda hücre yapılarına zarar verir, ancak kontrollü miktarda bazı savunma işlevlerinde kullanılabilir. Yani iki yönlü bir maddedir. Miktarı önemlidir."},{"t":"Katalazın rolü","a":"Miktarı ayarlar","d":"Peroksizomdaki katalaz, fazla hidrojen peroksiti parçalayarak miktarını düşük tutar. Böylece zararlı seviyeye çıkması önlenir. Katalaz bir denge sağlar."},{"t":"Önem","a":"Güvenli seviye","d":"Katalaz dengesi, hidrojen peroksitin hücreye zarar vermeyecek seviyede kalmasını sağlar. Aşırı birikim engellenir. Bu denge hücre sağlığı için önemlidir."}],"ans":"Katalaz, hidrojen peroksiti güvenli seviyede tutarak hem zararlı birikimini önler hem de kontrollü kullanımını mümkün kıldığı için önemlidir."},{"q":"Bir bitki tohumu çimlenirken depo yağlarını enerjiye çevirmek için peroksizomları kullanır. Bu durum peroksizomun yağ metabolizmasındaki rolünü nasıl destekler?","steps":[{"t":"Tohumdaki depo","a":"Yağ deposu","d":"Çimlenen tohumda enerji depo yağları biçiminde saklanır. Bu yağların kullanılabilmesi için parçalanması gerekir. Çimlenme için enerjiye dönüştürülür."},{"t":"Peroksizomun görevi","a":"Yağ yıkımı","d":"Peroksizomlar yağ asitlerinin yıkımında görev alır. Tohumda depo yağlar peroksizomlarda parçalanır. Böylece yağdan enerji elde edilmeye başlanır."},{"t":"Destek","a":"Yağ metabolizması","d":"Tohumda yağların peroksizomda yıkılması, bu organelin yağ metabolizmasında rol aldığını destekler. Yani peroksizom yağ işlemekle ilgilidir. Bu, gözlemle doğrulanır."}],"ans":"Tohumda depo yağların peroksizomlarda yıkılması, peroksizomun yağ asidi metabolizmasında etkin rol oynadığını destekler."},{"q":"Lizozom enzimleri yapısal olarak proteindir ve ribozomlarda üretilir. Bir enzimin ribozomdan lizozoma kadar izlediği yolu kısaca açıkla.","steps":[{"t":"Üretim","a":"Ribozom-ER","d":"Lizozom enzimleri, ER üzerindeki ribozomlarda üretilir ve ER'nin içine girer. Burada ön işlemden geçer. Sonra kesecikle Golgi'ye gönderilir."},{"t":"İşleme","a":"Golgi paketler","d":"Enzim Golgi'de işlenir ve lizozoma yönlendiren belirteçle etiketlenir. Trans yüzde kofula paketlenir. Bu koful lizozoma dönüşür."},{"t":"Hedefe ulaşma","a":"Lizozom oluşur","d":"Belirtece göre koful lizozom hâline gelir ve enzimi içerir. Böylece enzim hedefine ulaşmış olur. Lizozom sindirim yapmaya hazırdır."}],"ans":"Enzim ribozom-ER'de üretilir, Golgi'de işlenip etiketlenir ve trans yüzden ayrılan kofulle lizozom hâline gelerek hedefine ulaşır."},{"q":"Lizozomal depo hastalıkları, belirli bir lizozom enziminin eksikliğinde o enzimin parçalaması gereken maddenin hücrede birikmesiyle ortaya çıkar. Bu durum lizozomun normal işlevini nasıl ortaya koyar?","steps":[{"t":"Normal işlev","a":"Madde parçalama","d":"Normalde lizozom enzimleri belirli maddeleri parçalar. Her enzim belirli bir maddeden sorumludur. Bu sayede maddeler birikmez."},{"t":"Enzim eksikse","a":"Madde birikir","d":"Bir enzim eksik olursa, onun parçalaması gereken madde parçalanamaz. Bu madde lizozomda ve hücrede birikir. Birikim hastalığa yol açar."},{"t":"Ortaya koyduğu","a":"Parçalama görevi kritik","d":"Eksiklik durumunda birikim olması, lizozomun normalde sürekli madde parçaladığını ortaya koyar. Bu görev hücre için kritiktir. İşlevi aksarsa hücre zarar görür."}],"ans":"Enzim eksikliğinde maddenin birikmesi, lizozomun normalde belirli maddeleri sürekli parçalayan kritik bir görevi olduğunu ortaya koyar."},{"q":"Bir hücrede besin azaldığında otofaji artar; hücre kendi bazı yapılarını parçalayıp yapı taşı ve enerji elde eder. Bu durumda lizozomun rolü hücrenin hayatta kalmasına nasıl katkı sağlar?","steps":[{"t":"Besin azlığı","a":"Kaynak ihtiyacı","d":"Besin azaldığında hücrenin yapı taşı ve enerjiye ihtiyacı artar. Dışarıdan yeterli kaynak gelmez. Hücre içeriden kaynak bulmalıdır."},{"t":"Otofaji artışı","a":"İç kaynak kullanımı","d":"Hücre, otofajiyle kendi az gerekli yapılarını parçalar. Bu yapılar lizozomda sindirilir. Açığa çıkan yapı taşları yeniden kullanılır."},{"t":"Lizozumun katkısı","a":"Hayatta kalma","d":"Lizozom bu yapıların parçalanmasını sağlayarak hücreye kaynak sunar. Böylece hücre zor dönemi atlatabilir. Lizozom hayatta kalmaya doğrudan katkı sağlar."}],"ans":"Besin azlığında lizozom, otofajiyle parçaladığı yapılardan yapı taşı ve enerji sağlayarak hücrenin hayatta kalmasına katkı sunar."},{"q":"Peroksizomlar yeni proteinlerini ER'den almaz; proteinleri doğrudan sitoplazmadan alır ve mevcut peroksizomlardan bölünerek çoğalabilir. Bu özellik peroksizomu salgı yolu organellerinden nasıl ayırır?","steps":[{"t":"Salgı yolu organelleri","a":"ER'den protein","d":"Lizozom gibi salgı yolu organelleri proteinlerini ER-Golgi yolundan alır. Yani proteinler keseciklerle taşınır. Bu yol salgı sistemine bağlıdır."},{"t":"Peroksizomun yolu","a":"Sitoplazmadan protein","d":"Peroksizom proteinlerini doğrudan sitoplazmadan alır ve mevcut peroksizomlardan bölünerek çoğalır. ER-Golgi yolunu kullanmaz. Farklı bir yol izler."},{"t":"Ayrım","a":"Bağımsız çoğalma","d":"Peroksizom, protein alımı ve çoğalması bakımından salgı yolundan bağımsızdır. Bu onu lizozomdan ayırır. Köken ve çoğalma yolu farklıdır."}],"ans":"Peroksizom proteinlerini sitoplazmadan alıp bölünerek çoğaldığı için, ER-Golgi yolunu kullanan lizozom gibi salgı yolu organellerinden ayrılır."},{"q":"Bir araştırmacı, oksijen kullanımı yüksek ve çok enerji üreten bir hücrede peroksizom sayısının da yüksek olduğunu buluyor. Bu ilişkinin olası nedenini açıkla.","steps":[{"t":"Yüksek oksijen kullanımı","a":"Çok tepkime","d":"Çok enerji üreten hücrede oksijenli tepkimeler yoğundur. Bu tepkimeler sırasında zararlı yan ürünler oluşabilir. Yan ürünler arasında hidrojen peroksit de vardır."},{"t":"Zararlı yan ürün","a":"Hidrojen peroksit","d":"Yoğun oksijen kullanımı daha çok hidrojen peroksit oluşumuna yol açar. Bu zararlı maddenin temizlenmesi gerekir. Temizlik işi artar."},{"t":"Peroksizom artışı","a":"Temizliği karşılar","d":"Artan hidrojen peroksiti parçalamak için daha çok peroksizom gerekir. Bu yüzden bu hücrelerde peroksizom sayısı yüksektir. İhtiyaç sayıyı belirler."}],"ans":"Yüksek oksijen kullanımı çok hidrojen peroksit oluşturur; bunu temizlemek için peroksizom sayısı arttığından bu ilişki ortaya çıkar."},{"q":"Lizozom hem dışarıdan alınan maddeleri (heterofaji) hem de hücrenin kendi yapılarını (otofaji) sindirir. Bu iki işlevin ortak yanı ve hücreye katkısı nedir?","steps":[{"t":"Heterofaji","a":"Dış madde sindirimi","d":"Lizozom dışarıdan alınan besin, bakteri gibi maddeleri sindirir; buna heterofaji denir. Dış kaynaklı maddeler parçalanır. Yapı taşları açığa çıkar."},{"t":"Otofaji","a":"İç yapı sindirimi","d":"Lizozom hücrenin kendi yaşlı yapılarını da sindirir; buna otofaji denir. İç kaynaklı yapılar parçalanır. Yine yapı taşları açığa çıkar."},{"t":"Ortak yan","a":"Parçalama ve geri kazanım","d":"Her iki işlevde de lizozom maddeyi parçalar ve yapı taşlarını hücreye geri kazandırır. Ortak yan parçalama ve geri dönüşümdür. Bu, hücreye kaynak ve temizlik sağlar."}],"ans":"Her ikisinde de lizozom maddeyi parçalayıp yapı taşlarını geri kazandırır; bu ortak işlev hücreye hem temizlik hem kaynak sağlar."},{"q":"Lizozom ve peroksizom ikisi de zarla çevrili kesecikler olmasına rağmen farklı organellerdir. İçerikleri, oluşumları ve görevleri bakımından bu iki organeli karşılaştır.","steps":[{"t":"İçerik farkı","a":"Sindirim enzimi / katalaz","d":"Lizozom çeşitli sindirim enzimleri içerir; peroksizom başlıca katalaz ve yağ yıkım enzimleri içerir. İçerdikleri enzimler farklıdır. Bu da görev farkını yaratır."},{"t":"Oluşum farkı","a":"Golgi / bölünme","d":"Lizozom ER-Golgi yolundan oluşur; peroksizom proteinini sitoplazmadan alıp mevcut peroksizomlardan bölünerek çoğalır. Oluşum yolları farklıdır. Köken bakımından ayrılırlar."},{"t":"Görev farkı","a":"Sindirim / zararsızlaştırma","d":"Lizozom hücre içi sindirim yapar; peroksizom hidrojen peroksiti parçalar ve yağ asitlerini yıkar. Görevleri farklıdır. İkisi farklı hücresel ihtiyaçlara hizmet eder."}],"ans":"Lizozom sindirim enzimleri içerip Golgi'den oluşur ve sindirim yapar; peroksizom katalaz içerip bölünerek çoğalır ve hidrojen peroksiti parçalayıp yağ yıkar."}],"zor":[{"q":"Bir fagosit akyuvarın bir bakteriyi yutmasından bakterinin tamamen parçalanmasına kadar olan süreci, organellerin rollerini belirterek sıralı açıkla.","steps":[{"t":"1. Yutma","a":"Fagositoz","d":"Akyuvar, bakteriyi hücre zarıyla sararak içine alır; bu olaya fagositoz denir. Bakteri bir zarla çevrili kofulun içinde kalır. Bu kofula fagozom denir."},{"t":"2. Enzim sağlama","a":"Golgi-lizozom","d":"Sindirim enzimleri ER'de üretilip Golgi'de paketlenmiş ve lizozom hâline gelmiştir. Bu lizozomlar enzim deposudur. Bakteriyi parçalamak için hazır beklerler."},{"t":"3. Birleşme","a":"Fagozom-lizozom","d":"Bakteriyi taşıyan fagozom, lizozomla birleşir. Lizozom enzimleri bakterinin üzerine boşalır. Asidik ortamda enzimler etkinleşir."},{"t":"4. Parçalama","a":"Sindirim tamamlanır","d":"Enzimler bakteriyi yapı taşlarına kadar parçalar. Yapı taşları hücreye geri kazandırılır, artıklar dışarı atılır. Böylece bakteri tamamen yok edilir."}],"ans":"Akyuvar bakteriyi fagositozla yutar, fagozom Golgi kökenli lizozomla birleşir ve lizozom enzimleri bakteriyi yapı taşlarına kadar parçalayarak yok eder."},{"q":"Peroksizomda yağ asitleri yıkılırken oluşan hidrojen peroksit, katalazla parçalanmasaydı hücrede ne tür zincirleme bir sorun ortaya çıkardı?","steps":[{"t":"Hidrojen peroksit oluşumu","a":"Yağ yıkımının yan ürünü","d":"Peroksizomda yağ asitleri yıkılırken hidrojen peroksit açığa çıkar. Bu zararlı bir oksitleyicidir. Sürekli üretilir."},{"t":"Katalaz olmasaydı","a":"Birikim","d":"Katalaz olmazsa hidrojen peroksit parçalanamaz ve birikir. Birikim arttıkça hücre molekülleri zarar görmeye başlar. Proteinler ve zarlar oksitlenir."},{"t":"Zincirleme etki","a":"Hücre hasarı","d":"Oksitlenen yapılar bozulur, bu da daha fazla hasara yol açar. Hasar büyüyerek hücre işlevlerini bozar. Sonunda hücre zarar görebilir veya ölebilir."},{"t":"Sonuç","a":"Katalaz hayati","d":"Bu zincir, katalazın hidrojen peroksit birikimini önleyerek hücreyi koruduğunu gösterir. Katalaz olmadan yağ yıkımı hücre için tehlikeli olurdu. Bu yüzden katalaz hayatidir."}],"ans":"Katalaz olmasaydı hidrojen peroksit birikir, hücre molekülleri oksitlenerek zincirleme hasar oluşur ve hücre zarar görürdü; bu da katalazın hayati olduğunu gösterir."},{"q":"Bir kurbağa larvasının (iribaşın) kuyruğu metamorfoz sırasında kaybolur ve bu süreçte kuyruk hücreleri lizozom enzimleriyle parçalanır. Bu olay lizozomun gelişimdeki rolünü nasıl gösterir?","steps":[{"t":"Kuyruğun kaybı","a":"Hücreler ortadan kalkar","d":"Metamorfoz sırasında iribaşın kuyruğundaki hücreler ortadan kalkar. Bu hücrelerin denetimli biçimde yok edilmesi gerekir. Yok etme rastgele değildir."},{"t":"Lizozumun rolü","a":"Hücreleri sindirir","d":"Lizozom enzimleri kuyruk hücrelerini parçalar ve ortadan kaldırır. Açığa çıkan yapı taşları geri kazanılır. Lizozom bu yıkımı gerçekleştirir."},{"t":"Gelişimdeki anlamı","a":"Şekillendirici yıkım","d":"Lizozom sadece temizlik yapmaz; gelişim sırasında gereksiz yapıları yıkarak vücudu şekillendirir. Bu, denetimli bir yıkımdır. Lizozom gelişimde aktif rol oynar."}],"ans":"Kuyruk hücrelerinin lizozom enzimleriyle parçalanması, lizozomun gelişim sırasında gereksiz yapıları denetimli biçimde yıkarak vücudu şekillendirdiğini gösterir."},{"q":"Lizozom enziminin eksikliğinde ortaya çıkan depo hastalıklarında, eksik enzime göre farklı maddelerin biriktiği görülür. Bu çeşitlilik lizozomun tek bir enzim mi yoksa enzim grubu mu içerdiğini gösterir?","steps":[{"t":"Farklı birikimler","a":"Eksik enzime özgü","d":"Her depo hastalığında farklı bir madde birikir ve her biri farklı bir enzim eksikliğine bağlıdır. Yani her enzim belirli bir maddeden sorumludur. Birikimler enzime göre değişir."},{"t":"Enzim çeşitliliği","a":"Çok enzim olmalı","d":"Farklı maddelerin parçalanması için farklı enzimler gerekir. Tek bir enzim tüm maddeleri parçalayamaz. Bu yüzden lizozomda çok sayıda enzim bulunmalıdır."},{"t":"Sonuç","a":"Enzim grubu","d":"Bu çeşitlilik, lizozomun tek enzim değil, geniş bir enzim grubu içerdiğini gösterir. Her enzim ayrı bir maddeyi parçalar. Lizozom çok yönlü bir sindirim organelidir."}],"ans":"Eksik enzime göre farklı maddelerin birikmesi, lizozomun tek bir enzim değil, çeşitli maddeleri parçalayan geniş bir enzim grubu içerdiğini gösterir."},{"q":"Bir hücrede otofaji süreci aşırı artarsa, hücre kendi gerekli yapılarını da parçalayabilir. Lizozom etkinliğinin denetlenmesinin neden gerekli olduğunu açıkla.","steps":[{"t":"Otofajinin yararı","a":"Yaşlı yapıyı temizler","d":"Otofaji normalde yaşlı ve hasarlı yapıları temizleyip yapı taşı geri kazandırır. Bu hücre için yararlıdır. Ancak miktarı kontrol edilmelidir."},{"t":"Aşırı otofaji","a":"Gerekli yapı kaybı","d":"Otofaji aşırı artarsa hücre işlevsel ve gerekli yapılarını da parçalamaya başlar. Bu durumda hücre işlevini sürdüremez. Aşırı yıkım zararlı olur."},{"t":"Denetimin gerekliliği","a":"Denge sağlanır","d":"Lizozom etkinliği denetlenirse otofaji sadece gereksiz yapılarla sınırlı kalır. Böylece yıkım ve korunum dengelenir. Denetim hücrenin sağlıklı kalmasını sağlar."}],"ans":"Lizozom etkinliği denetlenmezse otofaji gerekli yapıları da parçalayabilir; denetim, yıkımı gereksiz yapılarla sınırlayıp hücrenin sağlığını korur."},{"q":"Karaciğer hücrelerinde hem peroksizomlar (zararlı madde işleme) hem de yoğun düz endoplazmik retikulum birlikte bulunur. Bu birliktelik karaciğerin zararsızlaştırma işlevini nasıl açıklar?","steps":[{"t":"Düz ER'nin rolü","a":"Madde işleme","d":"Düz endoplazmik retikulum, ilaç ve zararlı maddelerin işlenmesinde görev alır. Karaciğerde bu işlemler yoğundur. Bu yüzden düz ER gelişmiştir."},{"t":"Peroksizomun rolü","a":"Yan ürün temizliği","d":"Bu işlemler sırasında hidrojen peroksit gibi zararlı yan ürünler oluşur. Peroksizomlar bu yan ürünleri parçalar. Böylece zararlı birikim önlenir."},{"t":"Birlikte işlev","a":"Tamamlayıcı sistem","d":"Düz ER zararlı maddeleri işlerken peroksizom oluşan zararlı yan ürünleri temizler. İkisi birbirini tamamlar. Bu birliktelik karaciğerin etkili zararsızlaştırma yapmasını sağlar."}],"ans":"Düz ER zararlı maddeleri işlerken peroksizom oluşan zararlı yan ürünleri parçalar; bu tamamlayıcı birliktelik karaciğerin etkili zararsızlaştırmasını sağlar."},{"q":"Lizozom enzimleri sitoplazmanın nötre yakın ortamında etkin değilken lizozomun asidik iç ortamında etkindir. Bu pH farkının nasıl bir koruma mekanizması oluşturduğunu açıkla.","steps":[{"t":"pH bağımlılığı","a":"Asidik ortamda etkin","d":"Lizozom enzimleri yalnızca asidik ortamda yüksek etkinlik gösterir. Lizozom içi bu asidik ortamı sağlar. Enzimler burada işlevseldir."},{"t":"Sitoplazma pH'ı","a":"Etkinlik düşük","d":"Sitoplazma nötre yakındır; bu ortamda lizozom enzimleri çok az etkinlik gösterir. Yani sızsalar bile zor çalışırlar. Etkinlikleri büyük ölçüde düşer."},{"t":"Koruma mekanizması","a":"İki katlı güvenlik","d":"Zarın yanında pH farkı da bir koruma katmanı oluşturur. Enzim sızsa bile nötr sitoplazmada zarar veremez. Böylece hücre iki katlı korunur."}],"ans":"Enzimler yalnızca asidik lizozom içinde etkin olduğundan, nötr sitoplazmaya sızsalar bile çalışamaz; bu pH farkı zara ek bir ikinci güvenlik katmanı oluşturur."},{"q":"Bir hücrede Golgi aygıtı işlev görmezse lizozom oluşumu da aksar. Bu zincirleme etki, organeller arası bağımlılığı nasıl örneklendirir?","steps":[{"t":"Golgi-lizozom bağı","a":"Golgi lizozom yapar","d":"Lizozom enzimleri Golgi'de işlenip paketlenerek lizozom hâline gelir. Yani Golgi lizozom oluşumunda zorunludur. Golgi olmadan lizozom oluşamaz."},{"t":"Golgi durması","a":"Lizozom oluşamaz","d":"Golgi işlev görmezse enzimler işlenip paketlenemez. Lizozom kofulu oluşturulamaz. Böylece lizozom oluşumu aksar."},{"t":"Bağımlılık örneği","a":"Organeller birbirine bağlı","d":"Bir organelin bozulması başka bir organeli etkiler. Bu, organellerin birbirine bağımlı çalıştığını gösterir. Hücre bütünleşik bir sistemdir."}],"ans":"Golgi durunca enzimler paketlenemediği için lizozom oluşmaz; bu zincirleme etki, organellerin birbirine bağımlı, bütünleşik bir sistem oluşturduğunu örneklendirir."},{"q":"Peroksizomlar bölünerek çoğalabildiği gibi sayıları hücre ihtiyacına göre değişir; örneğin yağdan zengin beslenmede sayıları artar. Bu uyum yeteneği hücre için nasıl bir avantaj sağlar?","steps":[{"t":"Yağdan zengin beslenme","a":"Çok yağ yıkımı","d":"Yağdan zengin beslenmede hücreye çok yağ asidi gelir. Bu yağların yıkılması gerekir. Yağ yıkım işi artar."},{"t":"Peroksizom artışı","a":"İş yükünü karşılar","d":"Yağ yıkımında görevli peroksizomlar bölünerek çoğalır ve sayıları artar. Böylece artan iş yükü karşılanır. Hücre yağları etkili biçimde işler."},{"t":"Avantaj","a":"Esnek uyum","d":"Peroksizom sayısının ihtiyaca göre değişmesi, hücreye esnek uyum imkânı verir. Hücre koşullara hızla uyum sağlar. Bu da kaynakların verimli kullanımıdır."}],"ans":"Peroksizom sayısının ihtiyaca göre artması, hücreye değişen koşullara esnek uyum sağlama ve kaynakları verimli kullanma avantajı verir."},{"q":"Hücre içine alınan bir madde, önce bir kofulla çevrilir, sonra lizozomla birleşir ve enzimlerle parçalanır. Bu sürecin (hücre içi sindirim) zar sistemleriyle bağlantısını açıkla.","steps":[{"t":"Madde alımı","a":"Zar kofulu","d":"Hücre, maddeyi hücre zarından oluşan bir kofulla içine alır. Bu koful bir zar sistemidir. Madde zarla çevrilmiş olur."},{"t":"Lizozomla birleşme","a":"İki zar birleşir","d":"Madde kofulu ile lizozom, zarlarının birleşmesiyle kaynaşır. İki zarlı yapı tek bir bölme oluşturur. İçerikler bir araya gelir."},{"t":"Parçalama","a":"Enzimler iş başında","d":"Birleşen bölmede lizozom enzimleri maddeyi parçalar. Sindirim bir zarla çevrili güvenli bölmede gerçekleşir. Yapı taşları açığa çıkar."},{"t":"Zar sistemi bağlantısı","a":"Bütünleşik zar ağı","d":"Bu süreç, kofuller ve lizozomların zarlarının birbiriyle kaynaşıp ayrılabildiği bütünleşik bir zar sistemini gösterir. Hücre içi sindirim bu zar ağında yürür. Zar sistemleri sürecin temelidir."}],"ans":"Madde zar kofuluyla alınır, lizozomla zar kaynaşması yoluyla birleşir ve enzimlerle parçalanır; bu süreç hücrenin kofuller ve lizozomdan oluşan bütünleşik zar sistemine dayanır."},{"q":"Bir araştırmacı, hücredeki yaşlı mitokondrilerin zarla sarılıp lizozomla parçalandığını gözlemliyor (mitofaji). Bu özel otofaji türü lizozomun kalite kontroldeki rolünü nasıl gösterir?","steps":[{"t":"Yaşlı mitokondri","a":"İşlevsiz organel","d":"Mitokondriler zamanla yıpranır ve işlevini yitirebilir. İşlevsiz mitokondri hücreye zarar verebilir. Bunların ayıklanması gerekir."},{"t":"Mitofaji","a":"Seçici parçalama","d":"Yaşlı mitokondri bir zarla sarılır ve lizozomla birleşip parçalanır; buna mitofaji denir. Bu seçici bir otofajidir. Sadece bozuk organel hedeflenir."},{"t":"Lizozumun rolü","a":"Parçalama yeri","d":"Lizozom, sarılı mitokondriyi enzimleriyle parçalar. Yapı taşları geri kazanılır. Lizozom bu yıkımı gerçekleştirir."},{"t":"Kalite kontrol","a":"Bozuğu eler","d":"Sadece bozuk organellerin parçalanması, lizozomun bir kalite kontrol görevi yaptığını gösterir. İşlevsiz yapılar elenir, sağlamlar kalır. Böylece hücre sağlığı korunur."}],"ans":"Mitofajide yaşlı mitokondrinin seçici biçimde lizozomda parçalanması, lizozomun bozuk organelleri eleyerek hücrede kalite kontrol görevi yaptığını gösterir."},{"q":"Lizozom (asidik, sindirim enzimleri) ile peroksizom (katalaz, oksidatif tepkimeler) farklı iç ortamlara sahiptir. Bu iç ortam farkı, her organelin görevine nasıl uyum sağlar?","steps":[{"t":"Lizozum ortamı","a":"Asidik","d":"Lizozomun iç ortamı asidiktir; çünkü sindirim enzimleri asidik ortamda en iyi çalışır. Bu ortam enzim etkinliğini destekler. İç ortam göreve uyumludur."},{"t":"Peroksizom ortamı","a":"Oksidatif tepkimelere uygun","d":"Peroksizomun iç ortamı katalaz ve oksidatif tepkimelere uygundur. Hidrojen peroksitin parçalanması burada verimli olur. Bu ortam farklı enzimler için uygundur."},{"t":"Uyum","a":"Ortam göreve özgü","d":"Her organelin iç ortamı, içerdiği enzimlerin en iyi çalıştığı koşulları sağlar. Bu sayede görevler verimli yapılır. İç ortam farkı, görev uzmanlaşmasının bir parçasıdır."}],"ans":"Lizozumun asidik ortamı sindirim enzimlerine, peroksizomun ortamı katalaz ve oksidatif tepkimelere uyar; bu iç ortam farkı her organelin görevine özgü verim sağlar."},{"q":"Bir hücrede sindirim enzimleri Golgi'de mannoz-6-fosfatla etiketlenmezse lizozoma gidemez ve dışarı salgılanır. Bu durum lizozom oluşumunun salgı yoluyla nasıl iç içe olduğunu gösterir?","steps":[{"t":"Etiketin işlevi","a":"Lizozom adresi","d":"Mannoz-6-fosfat etiketi, sindirim enzimlerini lizozoma yönlendirir. Etiketsiz enzim doğru hedefe gidemez. Etiket bir adres gibidir."},{"t":"Etiket yoksa","a":"Salgı yoluna girer","d":"Etiketlenmeyen enzimler lizozoma değil, varsayılan olarak salgı yoluna girer ve dışarı verilir. Yani salgı yolu enzimlerin alternatif rotasıdır. Bu, iki yolun aynı sistemden ayrıldığını gösterir."},{"t":"İç içe oluş","a":"Ortak Golgi yolu","d":"Hem lizozom oluşumu hem salgı, Golgi'den geçen aynı yolun dallarıdır. Etiket, enzimi salgıdan ayırıp lizozoma yönlendirir. Demek ki lizozom oluşumu salgı yoluyla iç içedir."}],"ans":"Etiketsiz enzimlerin salgı yoluna girmesi, lizozom oluşumunun aynı Golgi yolunun bir dalı olduğunu, yani salgı yoluyla iç içe geçtiğini gösterir."},{"q":"Bir hücrede hem lizozom hem peroksizom sayısı düşükse, hangi iki temel işlev birlikte aksar ve bunun hücreye toplam etkisi ne olur?","steps":[{"t":"Lizozom azlığı","a":"Sindirim aksar","d":"Lizozom sayısı düşükse hücre içi sindirim ve temizlik yetersiz kalır. Yaşlı yapılar ve alınan maddeler parçalanamaz. Bunlar birikmeye başlar."},{"t":"Peroksizom azlığı","a":"Zararsızlaştırma aksar","d":"Peroksizom azsa hidrojen peroksit parçalanamaz ve yağ yıkımı yetersiz kalır. Zararlı maddeler birikir. Oksidatif hasar artar."},{"t":"Birlikte aksama","a":"İki temel işlev","d":"Aynı anda hücre içi sindirim ve zararsızlaştırma işlevleri aksar. İkisi de hücre temizliği ve korunmasıyla ilgilidir. Birlikte aksamaları büyük sorun yaratır."},{"t":"Toplam etki","a":"Birikim ve hasar","d":"Parçalanamayan maddeler ve zararlı yan ürünler birikir, oksidatif hasar artar. Hücre giderek işlevini yitirir. Toplam etki hücre sağlığının ciddi biçimde bozulmasıdır."}],"ans":"Hücre içi sindirim ve zararsızlaştırma birlikte aksar; parçalanamayan maddeler ve zararlı yan ürünler birikip oksidatif hasar artar, bu da hücre sağlığını ciddi biçimde bozar."},{"q":"Lizozom ve peroksizomun ikisi de hücrede \"temizlik ve koruma\" görevi yaparken farklı mekanizmalar kullanır. Bu işlev benzerliğine rağmen iki ayrı organel olmalarının hücreye sağladığı avantajı açıkla.","steps":[{"t":"Ortak amaç","a":"Temizlik ve koruma","d":"Lizozom ve peroksizom her ikisi de hücreyi zararlılardan koruyup temizler. Ortak amaçları hücre sağlığıdır. Ancak yöntemleri farklıdır."},{"t":"Farklı mekanizma","a":"Sindirim / oksidatif","d":"Lizozom asidik sindirim enzimleriyle parçalar; peroksizom katalaz ve oksidatif tepkimelerle çalışır. Farklı kimyasal koşullar gerektirirler. Bu yüzden ayrı bölmelerde olmalıdırlar."},{"t":"Ayrı olma avantajı","a":"Uzmanlaşma ve güvenlik","d":"İki ayrı organel, her görevin kendine özgü koşullarda ve birbirini etkilemeden yapılmasını sağlar. Bu uzmanlaşma verimi artırır, güçlü maddelerin karışmasını önler. Böylece hücre hem verimli hem güvenli temizlik yapar."}],"ans":"Ayrı organeller, farklı kimyasal koşullar gerektiren sindirim ve oksidatif temizliğin birbirini etkilemeden, uzmanlaşmış ve güvenli biçimde yapılmasını sağlar."}]}},"sitoiskelet":{"ilkokul":{"kolay":[{"q":"Hücrenin içinde, ona şekil ve destek veren ince ip benzeri yapılara ne ad verilir?","steps":[{"t":"Sorunun anlamı","a":"Hücre içi destek yapısı aranıyor","d":"Hücre yumuşak bir yapıdır ve dağılmaması için içeriden desteğe ihtiyaç duyar. Tıpkı bir çadırın iplerle ayakta durması gibi hücre de ince iplerle desteklenir."},{"t":"Yapının adı","a":"Hücre iskeleti","d":"Hücrenin içini dolduran ince iplikler ağı hücre iskeleti olarak adlandırılır. Bu iplikler hücreye biçim verir ve onu sağlam tutar."}],"ans":"Hücre iskeleti"},{"q":"Hücre iskeleti hücreye hangi iki temel görevi sağlar?","steps":[{"t":"Birinci görev","a":"Şekil verir","d":"Hücre iskeleti hücrenin belirli bir biçimde kalmasını sağlar. Bu sayede hücre dağılıp şekilsiz hale gelmez."},{"t":"İkinci görev","a":"Destek sağlar","d":"Hücre iskeleti hücre içindeki yapıları yerinde tutar ve hücreye dayanıklılık verir. Böylece hücre dış etkilere karşı daha güçlü olur."}],"ans":"Hücreye şekil verir ve destek sağlar"},{"q":"Hücre iskeletini bir çadırın iplerine benzetirsek, çadırın bezi hücrede neye benzer?","steps":[{"t":"Çadırdaki rol","a":"İpler çadırı tutar","d":"Çadırın ipleri ve direkleri çadırı ayakta tutar. Bunlar hücredeki iskelet ipliklerine benzer."},{"t":"Hücredeki karşılığı","a":"Hücre zarı dış örtüdür","d":"Çadırın dış bezi gibi hücrenin de dışını saran bir örtüsü vardır; buna hücre zarı denir. İskelet ipleri bu örtüyü ve hücreyi içeriden destekler."}],"ans":"Hücre zarı"},{"q":"Hücre iskeleti olmasaydı hücrenin şekli nasıl olurdu?","steps":[{"t":"İskeletin işlevi","a":"Şekli korur","d":"Hücre iskeleti hücreye belirli bir biçim kazandırır. Bu iplikler olmadan hücreyi ayakta tutacak bir destek kalmaz."},{"t":"Sonuç","a":"Şekilsiz olurdu","d":"Destek olmadığında hücre dağılır ve belirgin bir şekli kalmaz. Yumuşak ve gevşek bir hale gelirdi."}],"ans":"Şekilsiz, dağılmış bir hale gelirdi"},{"q":"Hücre iskeleti hücrenin neresinde bulunur?","steps":[{"t":"Hücrenin içi","a":"Sitoplazma içinde","d":"Hücrenin içi sitoplazma adı verilen sıvımsı bir madde ile doludur. Hücre iskeleti bu sıvının içine yayılmış durumdadır."},{"t":"Konumu","a":"Tüm hücre içine yayılır","d":"İskelet iplikleri hücrenin bir ucundan diğerine kadar uzanır. Böylece hücrenin her yerine destek verir."}],"ans":"Hücrenin içinde, sitoplazmada"}],"zor":[{"q":"Hücre iskeleti hareketli midir, yoksa sabit bir yapı mıdır? Neden?","steps":[{"t":"İlk düşünce","a":"Kemik gibi sabit değildir","d":"Bizim iskeletimizdeki kemikler serttir ve kolayca değişmez. Ancak hücre iskeleti kemik gibi katı değildir."},{"t":"Gerçek durum","a":"Sürekli değişir","d":"Hücre iskeleti iplikleri gerektiğinde yapılır ve gerektiğinde sökülür. Bu sayede hücre şeklini değiştirebilir ve hareket edebilir."}],"ans":"Hareketlidir; iplikleri kurulup sökülebildiği için sürekli değişir"},{"q":"Bazı hücrelerin yüzeyinde bulunan ve hareket etmelerini sağlayan kıl benzeri uzantılar nelerdir?","steps":[{"t":"Yüzeydeki uzantılar","a":"Kıl benzeri yapılar","d":"Bazı hücrelerin dışında küçük tüy veya kuyruk gibi uzantılar bulunur. Bu uzantılar iskelet ipliklerinden oluşur."},{"t":"Görevleri","a":"Hareket sağlarlar","d":"Bu uzantılar ileri geri sallanarak hücrenin sıvı içinde ilerlemesini sağlar. Buna sil ve kamçı denir."}],"ans":"Sil ve kamçı"},{"q":"Bir hücre yer değiştirirken hücre iskeletinin görevi nedir?","steps":[{"t":"Hareketin kaynağı","a":"İskelet şekil değiştirir","d":"Hücre hareket ederken bir tarafını öne uzatır. Bu uzamayı sağlayan, iskelet ipliklerinin yeniden düzenlenmesidir."},{"t":"Sonuç","a":"Hücre ilerler","d":"İplikler bir yönde kurulup diğer yönde sökülerek hücreyi iter. Böylece hücre yavaşça yer değiştirir."}],"ans":"Şeklini değiştirerek hücrenin hareket etmesini sağlar"},{"q":"Hücre iskeleti, hücre içindeki küçük yapıların taşınmasına nasıl yardımcı olur?","steps":[{"t":"Yapıların durumu","a":"Yapılar yer değiştirir","d":"Hücre içinde organel adı verilen küçük yapılar vardır. Bunların bazen bir yerden başka bir yere taşınması gerekir."},{"t":"İskeletin rolü","a":"Yol görevi görür","d":"İskelet iplikleri hücre içinde demiryolu gibi yollar oluşturur. Küçük yapılar bu yollar üzerinde kayarak taşınır."}],"ans":"Yol görevi görerek yapıların taşınmasını sağlar"},{"q":"Hücre bölünürken oluşan ve kromozomları ayıran iplik benzeri yapı hangi sisteme aittir?","steps":[{"t":"Bölünme anı","a":"Kromozomlar ayrılır","d":"Hücre ikiye bölünürken içindeki kalıtım maddeleri iki yeni hücreye paylaştırılır. Bu paylaştırma sırasında ince iplikler oluşur."},{"t":"İpliklerin kaynağı","a":"İğ iplikleri","d":"Bu ipliklere iğ iplikleri denir ve hücre iskeletinden yapılır. Kromozomları çekerek iki kutba doğru ayırırlar."}],"ans":"Hücre iskeletine (iğ iplikleri)"}]},"ortaokul":{"kolay":[{"q":"Hücre iskeletini oluşturan üç ana iplik tipinden en kalın olanının adı nedir?","steps":[{"t":"Üç iplik tipi","a":"Farklı kalınlıkta iplikler","d":"Hücre iskeleti üç farklı tip iplikten oluşur. Bunlar kalınlıklarına göre birbirinden ayrılır."},{"t":"En kalın olan","a":"Mikrotübül","d":"Bu üç tip arasında en kalın olanı mikrotübüldür. İçi boş bir boru şeklindedir ve hücreye sağlam destek verir."}],"ans":"Mikrotübül"},{"q":"Hücre iskeletindeki en ince iplik tipi olan ve aktin proteininden yapılan yapı nedir?","steps":[{"t":"İncelik karşılaştırması","a":"En ince tip aranıyor","d":"Hücre iskeletinin üç ipliğinden biri diğerlerinden belirgin biçimde daha incedir. Bu ince iplikler hücrenin yüzeyine yakın bulunur."},{"t":"Yapısı","a":"Aktinden oluşur","d":"Bu en ince iplikler aktin adlı proteinden yapılır ve mikrofilament olarak adlandırılır. Hücre yüzeyine ve şekline destek verirler."}],"ans":"Mikrofilament (aktin filamenti)"},{"q":"Sil ve kamçının yapısında hangi hücre iskeleti ipliği bulunur?","steps":[{"t":"Sil ve kamçı","a":"Hareket uzantıları","d":"Sil ve kamçı, hücrenin hareketini sağlayan uzantılardır. İçleri düzenli iplik demetleriyle doludur."},{"t":"İçindeki iplik","a":"Mikrotübül","d":"Bu uzantıların içi mikrotübüllerle döşelidir. Mikrotübüllerin kayması sil ve kamçının kıvrılıp sallanmasını sağlar."}],"ans":"Mikrotübül"},{"q":"Mikrotübüllerin üretilmesini düzenleyen ve hayvan hücrelerinde çekirdeğin yakınında bulunan yapı nedir?","steps":[{"t":"Mikrotübül kaynağı","a":"Bir merkez var","d":"Mikrotübüller hücrede rastgele değil, belirli bir merkezden başlayarak uzar. Bu merkez hayvan hücrelerinde çekirdeğe yakındır."},{"t":"Merkezin adı","a":"Sentrozom","d":"Bu merkeze sentrozom denir ve içinde sentriyoller bulunur. Mikrotübüllerin düzenli biçimde oluşmasını yönetir."}],"ans":"Sentrozom"},{"q":"Hücre iskeletinin üç temel görevini sayınız.","steps":[{"t":"Birinci ve ikinci görev","a":"Şekil ve destek","d":"Hücre iskeleti hücreye belirli bir biçim kazandırır ve onu mekanik olarak destekler. Bu sayede hücre dağılmaz ve dayanıklı kalır."},{"t":"Üçüncü görev","a":"Hareket ve taşıma","d":"İskelet ayrıca hücre içi taşımayı, organel hareketini ve hücrenin yer değiştirmesini sağlar. Ayrıca sil-kamçı hareketinde de görev alır."}],"ans":"Şekil verme, destek sağlama, hareket ve hücre içi taşıma"}],"zor":[{"q":"Mikrotübül, mikrofilament ve ara filamentleri kalınlıklarına göre büyükten küçüğe sıralayınız.","steps":[{"t":"En kalın","a":"Mikrotübül","d":"Mikrotübül içi boş bir boru biçimindedir ve yaklaşık 25 nanometre çapındadır. Üç iplik tipi içinde en kalın olanıdır."},{"t":"Orta kalınlık","a":"Ara filament","d":"Ara filamentler yaklaşık 10 nanometre çapındadır ve adından da anlaşılacağı gibi orta kalınlıktadır. Hücreye mekanik dayanıklılık verirler."},{"t":"En ince","a":"Mikrofilament","d":"Mikrofilamentler yaklaşık 7 nanometre çapındadır ve en ince iplik tipidir. Aktin proteininden oluşur."}],"ans":"Mikrotübül > ara filament > mikrofilament"},{"q":"Hücre içinde organellerin bir yerden başka bir yere taşınmasında mikrotübüller nasıl bir rol oynar?","steps":[{"t":"Mikrotübül rayları","a":"Yol oluştururlar","d":"Mikrotübüller hücre içinde demiryolu gibi uzun raylar oluşturur. Organeller ve kesecikler bu raylar üzerinde hareket eder."},{"t":"Taşıma proteinleri","a":"Motor proteinler taşır","d":"Mikrotübül rayları üzerinde yürüyen motor proteinler vardır. Bu proteinler organelleri tutar ve ray boyunca hedefe taşır."}],"ans":"Mikrotübüller ray görevi görür, motor proteinler organelleri bu raylar üzerinde taşır"},{"q":"Ara filamentlerin diğer iki iplik tipinden farkı olan başlıca görevi nedir?","steps":[{"t":"Diğer ipliklerin işi","a":"Hareket ve taşıma","d":"Mikrotübül ve mikrofilamentler hücre içi taşıma ve hareket gibi işlerde aktif görev alır. Bunlar sürekli kurulup sökülebilen yapılardır."},{"t":"Ara filamentin işi","a":"Mekanik dayanıklılık","d":"Ara filamentler daha kalıcıdır ve hücreyi gerilme kuvvetlerine karşı dayanıklı kılar. Özellikle deri gibi mekanik strese maruz kalan dokularda boldur."}],"ans":"Hücreye mekanik dayanıklılık sağlamak (gerilmeye karşı koruma)"},{"q":"Hücre bölünmesi sırasında iğ ipliklerini oluşturan iplik tipi hangisidir ve görevi nedir?","steps":[{"t":"İğ ipliği yapısı","a":"Mikrotübülden yapılır","d":"Hücre bölünürken sentrozomdan uzanan iğ iplikleri oluşur. Bu iplikler mikrotübüllerden meydana gelir."},{"t":"Görevi","a":"Kromozomları ayırır","d":"İğ iplikleri kromozomlara tutunur ve onları hücrenin iki kutbuna çeker. Böylece kalıtım maddesi iki yeni hücreye eşit paylaştırılır."}],"ans":"Mikrotübül; kromozomları kutuplara çekerek eşit paylaştırır"},{"q":"Akıcı bir besin alan amip benzeri bir hücrenin yalancı ayak (yalancı kol) çıkarmasında hangi iskelet elemanı rol alır?","steps":[{"t":"Yalancı ayak nedir","a":"Hücre uzantısı","d":"Amip gibi hücreler hareket ederken gövdelerinin bir kısmını öne doğru uzatır. Bu uzantıya yalancı ayak denir."},{"t":"Rol alan iplik","a":"Aktin filamentleri","d":"Yalancı ayak, aktinden oluşan mikrofilamentlerin bir uçta hızla kurulmasıyla öne uzar. Bu sayede hücre yön değiştirip ilerleyebilir."}],"ans":"Mikrofilamentler (aktin)"}]},"lise":{"kolay":[{"q":"Hücre iskeletini oluşturan üç filament tipini ve her birinin temel yapı proteinini eşleştiriniz.","steps":[{"t":"Mikrotübül","a":"Tübulin","d":"Mikrotübüller alfa ve beta tübulin alt birimlerinin birleşmesiyle oluşur. İçi boş, boru biçimli ve en kalın filament tipidir."},{"t":"Mikrofilament","a":"Aktin","d":"Mikrofilamentler globüler aktin moleküllerinin sarmal biçimde dizilmesiyle oluşur. En ince filament tipidir ve hücre yüzeyine yakındır."},{"t":"Ara filament","a":"Çeşitli proteinler (örneğin keratin)","d":"Ara filamentler keratin, vimentin, lamin gibi farklı liflerden oluşabilir. Kalınlıkları diğer iki tipin arasındadır ve mekanik dayanıklılık verir."}],"ans":"Mikrotübül-tübulin, mikrofilament-aktin, ara filament-keratin/vimentin gibi proteinler"},{"q":"Mikrotübüllerin polaritesi ne demektir ve büyüme genellikle hangi uçtan olur?","steps":[{"t":"Polarite kavramı","a":"İki ucu farklıdır","d":"Mikrotübülün iki ucu yapı bakımından özdeş değildir; biri artı, diğeri eksi uç olarak adlandırılır. Bu farka polarite denir."},{"t":"Büyüme ucu","a":"Artı uçtan büyür","d":"Tübulin alt birimleri çoğunlukla artı uca eklenerek mikrotübülü uzatır. Eksi uç ise genellikle sentrozoma bağlı ve kararlıdır."}],"ans":"İki ucun farklı olması; büyüme genellikle artı (+) uçtan olur"},{"q":"Sentrozomun içinde bulunan ve birbirine dik konumlanmış silindirik yapılar nelerdir?","steps":[{"t":"Sentrozom yapısı","a":"İçinde sentriyol var","d":"Hayvan hücrelerinde çekirdeğe yakın bulunan sentrozom, mikrotübül oluşumunu düzenler. İçinde özel silindirik yapılar barındırır."},{"t":"Sentriyoller","a":"Birbirine dik çift","d":"Bu silindirik yapılara sentriyol denir ve genellikle birbirine dik açıyla durur. Mikrotübül üçlülerinden oluşan dokuz demet içerirler."}],"ans":"Sentriyoller"},{"q":"Silin iç yapısındaki mikrotübül dizilişini tanımlayan düzen nasıl ifade edilir?","steps":[{"t":"İç düzen","a":"Düzenli mikrotübüller","d":"Hareketli sil ve kamçının içinde aksonem adı verilen düzenli bir mikrotübül demeti bulunur. Bu demet belirli bir geometriye sahiptir."},{"t":"Dizilişin adı","a":"Dokuz artı iki düzeni","d":"Çevrede dokuz mikrotübül çifti, ortada ise iki tek mikrotübül bulunur. Buna 9+2 düzeni denir."}],"ans":"9+2 düzeni (çevrede 9 çift, merkezde 2 tek mikrotübül)"},{"q":"Hücre içi vezikül taşımasında mikrotübüller üzerinde hareket eden iki ana motor protein ailesi hangileridir?","steps":[{"t":"Motor protein kavramı","a":"Raylarda yürüyen proteinler","d":"Mikrotübüller ray görevi görürken, üzerlerinde ATP harcayarak yürüyen motor proteinler bulunur. Bunlar yük olarak vezikül ve organel taşır."},{"t":"İki aile","a":"Kinezin ve dinein","d":"Kinezin genellikle artı uca doğru, dinein ise eksi uca doğru taşıma yapar. Böylece yükler hücre içinde iki yönde de taşınabilir."}],"ans":"Kinezin ve dinein"},{"q":"Mikrofilamentlerin (aktin) hücredeki başlıca dört işlevinden ikisini açıklayınız.","steps":[{"t":"Birinci işlev","a":"Hücre şekli ve korteks","d":"Aktin filamentleri hücre zarının hemen altında yoğun bir ağ oluşturarak hücre korteksini meydana getirir. Bu, hücre yüzeyine şekil ve dayanıklılık verir."},{"t":"İkinci işlev","a":"Hareket ve sitokinez","d":"Aktin, kas kasılmasında miyozinle birlikte çalışır ve amipsi harekette yalancı ayak oluşturur. Ayrıca hücre bölünmesi sonunda boğumlanmayı (sitokinez) sağlar."}],"ans":"Hücre korteksi/şekil, hareket (yalancı ayak/kas), sitokinez gibi işlevler"},{"q":"Bitki hücrelerinde sentriyol bulunmamasına rağmen iğ ipliklerinin oluşabilmesi neyi gösterir?","steps":[{"t":"Gözlem","a":"Sentriyolsüz bölünme","d":"Bitki hücrelerinde tipik sentriyol çiftleri yoktur, ancak hücreler yine de düzgün şekilde bölünür. İğ iplikleri sorunsuz oluşur."},{"t":"Çıkarım","a":"Merkez şart değil","d":"Bu durum, iğ ipliklerinin oluşması için mutlaka sentriyolün gerekmediğini gösterir. Bitkilerde mikrotübül organize eden bölgeler bu görevi üstlenir."}],"ans":"İğ ipliği oluşumu için sentriyolün zorunlu olmadığını gösterir"},{"q":"Akıcı mozaik bir hücrede mikrotübüllerin sürekli kurulup sökülmesine ne ad verilir?","steps":[{"t":"Dinamik yapı","a":"Kararsız uzunluk","d":"Mikrotübüller sabit kalmaz; uçları bazen hızla uzar, bazen aniden kısalır. Bu sürekli değişim hücrenin ihtiyaçlarına göre ayarlanır."},{"t":"Olayın adı","a":"Dinamik kararsızlık","d":"Bu uzayıp kısalma davranışına dinamik kararsızlık denir. Bu özellik mikrotübüllerin hızla yeniden düzenlenmesini sağlar."}],"ans":"Dinamik kararsızlık (dinamik instabilite)"},{"q":"Hayvan hücresinde sitokinez (sitoplazma bölünmesi) hangi iskelet yapısı tarafından gerçekleştirilir?","steps":[{"t":"Sitokinez nedir","a":"Sitoplazmanın ayrılması","d":"Çekirdek bölündükten sonra sitoplazmanın da ikiye ayrılması gerekir. Hayvan hücrelerinde bu, hücrenin ortadan boğumlanmasıyla olur."},{"t":"Boğumlanma halkası","a":"Aktin halkası","d":"Hücrenin orta kısmında aktin ve miyozinden oluşan bir kasılma halkası kurulur. Bu halka büzülerek hücreyi ikiye ayırır."}],"ans":"Aktin (mikrofilament) kasılma halkası"},{"q":"Mikrotübüllerin iki ana yapısal görevini (organel konumu ve hücre içi yollar) açıklayınız.","steps":[{"t":"Organel yerleşimi","a":"Organelleri konumlandırır","d":"Mikrotübüller hücre içinde golgi, endoplazmik retikulum gibi organellerin belirli konumlarda tutulmasını sağlar. Bu sayede organeller düzenli bir yerleşime sahip olur."},{"t":"Taşıma yolları","a":"Ray görevi görür","d":"Mikrotübüller vezikül ve organel taşıması için yollar oluşturur. Motor proteinler bu yollar üzerinde yük taşır."}],"ans":"Organelleri konumlandırma ve hücre içi taşıma yolları oluşturma"},{"q":"Bir nöronun (sinir hücresi) uzun aksonu boyunca madde taşınmasında hangi iskelet elemanı kritik öneme sahiptir?","steps":[{"t":"Aksonun durumu","a":"Çok uzun uzantı","d":"Sinir hücrelerinin aksonu metrelerce uzunluğa ulaşabilir. Hücre gövdesinde üretilen maddelerin akson ucuna ulaştırılması gerekir."},{"t":"Taşıma sistemi","a":"Mikrotübül yolları","d":"Akson boyunca uzanan mikrotübüller, motor proteinlerin yük taşıdığı raylar oluşturur. Bu sayede maddeler uzun mesafelere taşınır."}],"ans":"Mikrotübüller"},{"q":"Ara filamentlerin deri ve saç gibi yapılarda bulunan başlıca proteini nedir?","steps":[{"t":"Doku özelliği","a":"Mekanik dayanıklılık","d":"Deri ve saç gibi yapılar sürekli mekanik gerilmeye maruz kalır. Bu dokulardaki hücrelerin dayanıklı bir iskelet ağına ihtiyacı vardır."},{"t":"İlgili protein","a":"Keratin","d":"Bu dokulardaki ara filamentler büyük oranda keratin proteininden oluşur. Keratin hücrelere gerilmeye karşı yüksek dayanıklılık kazandırır."}],"ans":"Keratin"},{"q":"Mikrotübüllerin oluşumu için temel yapı taşı olan ve GTP bağlayan protein hangisidir?","steps":[{"t":"Yapı taşı","a":"Tübulin alt birimi","d":"Mikrotübüller alfa ve beta tübulin ikililerinin (dimer) üst üste eklenmesiyle uzar. Bu ikililer mikrotübülün temel yapı taşıdır."},{"t":"GTP bağlama","a":"Beta tübulin GTP bağlar","d":"Beta tübulin GTP molekülü bağlar ve bu, mikrotübülün uzaması ile kararlılığını düzenler. GTP hidrolizi dinamik kararsızlığı tetikler."}],"ans":"Tübulin (alfa-beta tübulin dimeri)"},{"q":"Akıcı mozaik modelde hücre korteksi nedir ve hangi filamentten oluşur?","steps":[{"t":"Korteks tanımı","a":"Zar altı ağ","d":"Hücre zarının hemen altında ince bir filament ağı bulunur. Bu yoğun tabakaya hücre korteksi denir."},{"t":"Yapısı","a":"Aktin ağı","d":"Hücre korteksi büyük oranda aktin mikrofilamentlerinden oluşur. Hücre yüzeyine mekanik destek verir ve şekil değişimlerini kontrol eder."}],"ans":"Zar altındaki aktin (mikrofilament) ağı; hücre yüzeyine destek verir"},{"q":"Kamçının dalga benzeri hareketini sağlayan, mikrotübül çiftleri arasında kayma oluşturan motor protein nedir?","steps":[{"t":"Aksonem yapısı","a":"Mikrotübül çiftleri","d":"Kamçının içindeki aksonem 9+2 düzeninde mikrotübül çiftleri içerir. Bu çiftler birbirine motor proteinlerle bağlıdır."},{"t":"Motor protein","a":"Dinein kayma yapar","d":"Aksonemdeki dinein kolları komşu mikrotübül çiftlerini birbiri üzerinde kaydırmaya çalışır. Bağlar kaymayı engelleyince bu kuvvet kamçıyı kıvırır ve dalga oluşturur."}],"ans":"Dinein (aksonemal dinein)"}],"zor":[{"q":"Dinamik kararsızlık mekanizmasında GTP başlığının (cap) kaybı neden hızlı kısalmaya (katastrof) yol açar? Açıklayınız.","steps":[{"t":"GTP başlığı","a":"Uzayan ucu korur","d":"Mikrotübül büyürken artı uca GTP bağlı tübulin eklenir ve uçta GTP başlığı oluşur. Bu başlık mikrotübül ucunu kararlı tutar ve uzamayı destekler."},{"t":"GTP hidrolizi","a":"GDP-tübulin oluşur","d":"Eklenen tübulin zamanla GTP yerine GDP içerir hale gelir. GDP bağlı tübulin daha kararsızdır ve eğilme eğilimindedir."},{"t":"Başlığın kaybı","a":"Hızlı kısalma","d":"Ekleme hidrolizden yavaş kalırsa GTP başlığı kaybolur ve GDP-tübulin uca ulaşır. Bu durumda mikrotübül hızla parçalanır; buna katastrof denir."}],"ans":"GTP başlığı kaybolunca GDP-tübulin açığa çıkar, kararsızlaşan uç hızla parçalanır (katastrof)"},{"q":"Kinezin ve dineinin mikrotübül üzerindeki taşıma yönlerini ve bunun hücredeki anlamını açıklayınız.","steps":[{"t":"Mikrotübül polaritesi","a":"Eksi uç merkeze yakın","d":"Hücrede mikrotübüllerin eksi uçları genellikle sentrozoma (hücre merkezine), artı uçları ise çevreye doğrudur. Bu yönelim taşıma yönünü belirler."},{"t":"Kinezin yönü","a":"Artı uca (çevreye)","d":"Kinezin genellikle artı uca doğru yürür ve yükleri hücre merkezinden çevreye taşır. Örneğin akson ucuna doğru madde taşır."},{"t":"Dinein yönü","a":"Eksi uca (merkeze)","d":"Dinein ise eksi uca doğru yürür ve yükleri çevreden hücre merkezine getirir. Böylece iki motor protein zıt yönlü taşıma yaparak hücre içi dağıtımı dengeler."}],"ans":"Kinezin artı uca (çevreye), dinein eksi uca (merkeze) taşır; çift yönlü taşıma sağlanır"},{"q":"Kolşisin mikrotübül oluşumunu engellerken, sitokalazin aktin polimerizasyonunu engeller. Bir hücreyi kolşisinle muamele ederseniz mitozda hangi aşama nasıl etkilenir?","steps":[{"t":"Kolşisinin etkisi","a":"Mikrotübül kurulmaz","d":"Kolşisin tübulin alt birimlerine bağlanarak mikrotübüllerin oluşmasını engeller. İğ iplikleri mikrotübülden yapıldığı için bu da etkilenir."},{"t":"İğ ipliği eksikliği","a":"İğ kurulamaz","d":"Mikrotübül oluşmadığından mitozda iğ iplikleri meydana gelemez. Kromozomlara tutunacak ve onları çekecek bir sistem oluşmaz."},{"t":"Sonuç","a":"Metafaz-anafaz durur","d":"Kromozomlar kutuplara ayrılamaz ve hücre anafaza geçemez; bölünme metafazda takılır. Bu nedenle kolşisin kromozom çalışmalarında kullanılır."}],"ans":"İğ iplikleri oluşamaz, kromozomlar ayrılamaz ve mitoz metafazda durur"},{"q":"Bir araştırmacı sitokalazin uygulanmış hayvan hücresinde sitokinezin gerçekleşmediğini gözlemliyor; bu sonucu açıklayınız.","steps":[{"t":"Sitokalazinin etkisi","a":"Aktin kurulamaz","d":"Sitokalazin aktin filamentlerinin uzamasını (polimerizasyonu) engeller. Böylece hücrede yeni aktin ağı kurulamaz."},{"t":"Kasılma halkası","a":"Aktin halkası oluşmaz","d":"Hayvan hücresinde sitokinez, aktin ve miyozinden oluşan bir kasılma halkasıyla gerçekleşir. Aktin oluşmayınca bu halka kurulamaz."},{"t":"Sonuç","a":"Boğumlanma yok","d":"Kasılma halkası olmadığından hücre ortadan boğumlanıp ikiye ayrılamaz. Çekirdek bölünse bile sitoplazma bölünmez ve iki çekirdekli hücre oluşabilir."}],"ans":"Aktin kasılma halkası kurulamadığından boğumlanma olmaz, sitokinez gerçekleşmez"},{"q":"Primer silyum (hareketsiz silyum) ile hareketli sil arasındaki yapısal farkı ve işlev farkını açıklayınız.","steps":[{"t":"Hareketli sil yapısı","a":"9+2 düzeni","d":"Hareketli sillerin aksonemi çevrede 9 mikrotübül çifti ve merkezde 2 tek mikrotübül içerir. Merkezdeki çift ve dinein kolları hareketi sağlar."},{"t":"Primer silyum yapısı","a":"9+0 düzeni","d":"Primer silyumda merkezi mikrotübül çifti bulunmaz, yani 9+0 düzenindedir. Bu nedenle tipik kayma hareketini gerçekleştiremez."},{"t":"İşlev farkı","a":"Algı vs hareket","d":"Hareketli siller sıvı veya hücreyi hareket ettirir. Primer silyum ise çoğunlukla bir algı (sinyal alma) anteni gibi davranır ve hücre dışı uyarıları algılar."}],"ans":"Hareketli sil 9+2 ve hareketlidir; primer silyum 9+0 ve hareketsiz, algı görevi görür"},{"q":"Sentrozomun (MTOC) hücre bölünmesindeki rolünü ve eksi uçların buradaki kararlılığını açıklayınız.","steps":[{"t":"MTOC kavramı","a":"Mikrotübül organize merkezi","d":"Sentrozom, mikrotübüllerin başlamasını (nukleasyon) sağlayan ana merkezdir; bu nedenle MTOC olarak adlandırılır. Burada gama-tübulin halkaları çekirdek görevi görür."},{"t":"Eksi uç kararlılığı","a":"Eksi uç tutulur","d":"Mikrotübüllerin eksi uçları sentrozomda tutulur ve kararlı kalır, büyüme artı uçtan dışa doğru olur. Bu, ışınsal bir mikrotübül dizilimi oluşturur."},{"t":"Bölünmedeki rol","a":"İki kutbu kurar","d":"Bölünmeden önce sentrozom ikiye katlanır ve hücrenin zıt kutuplarına gider. Buralardan uzayan mikrotübüller iğ ipliklerini ve iki kutuplu iğ aygıtını oluşturur."}],"ans":"Sentrozom mikrotübül nukleasyon merkezidir, eksi uçları tutar; iki kutba giderek iğ aygıtını kurar"},{"q":"Kartagener sendromunda dinein kollarındaki kusurun neden hem solunum yolu enfeksiyonlarına hem de erkek kısırlığına yol açtığını açıklayınız.","steps":[{"t":"Dineinin görevi","a":"Sil-kamçı hareketi","d":"Aksonemdeki dinein kolları mikrotübül çiftleri arasında kayma oluşturarak sil ve kamçı hareketini sağlar. Dinein kusurlu olunca bu uzantılar hareket edemez."},{"t":"Solunum etkisi","a":"Mukus temizlenemez","d":"Solunum yolundaki siller mukusu ve içindeki yabancı parçacıkları dışarı süpürür. Siller hareketsiz kalınca mukus birikir ve tekrarlayan enfeksiyonlar oluşur."},{"t":"Kısırlık etkisi","a":"Sperm hareketsiz","d":"Sperm hücresinin kuyruğu (kamçı) da dinein içeren bir aksoneme sahiptir. Dinein kusurlu olunca sperm yüzemez ve döllenme gerçekleşmez."}],"ans":"Dinein kusuru sil ve kamçıyı hareketsiz bırakır; mukus temizlenemez (enfeksiyon) ve sperm yüzemez (kısırlık)"},{"q":"Kas hücresinde aktin (ince) ve miyozin (kalın) filamentlerinin kasılmadaki etkileşimini kayma teorisiyle açıklayınız.","steps":[{"t":"Filamentlerin dizilimi","a":"İnce ve kalın iplikler","d":"Kas lifindeki sarkomerde aktin ince filamentler, miyozin ise kalın filamentler olarak düzenli biçimde dizilir. Bunlar birbiriyle örtüşecek şekilde yerleşmiştir."},{"t":"Köprü oluşumu","a":"Miyozin aktine tutunur","d":"Miyozin başları ATP enerjisi kullanarak aktin filamentlerine tutunur ve çapraz köprüler kurar. Sonra başlar bükülerek aktini içeri çeker."},{"t":"Kayma ve kısalma","a":"Sarkomer kısalır","d":"Aktin filamentleri miyozin üzerinde içe doğru kayar ve sarkomer kısalır. Tüm sarkomerlerin kısalması kasın bütününün kasılmasını sağlar."}],"ans":"Miyozin başları ATP ile aktine tutunup onu içe çeker, filamentler birbiri üzerinde kayar ve sarkomer kısalır"},{"q":"Bir hücrenin yara onarımı sırasında yara yüzeyine doğru göç etmesinde aktin dinamiklerinin rolünü açıklayınız.","steps":[{"t":"Öne uzama","a":"Lamellipodyum oluşur","d":"Göç eden hücre ön kenarında aktin filamentlerini hızla polimerize ederek yassı bir uzantı (lamellipodyum) oluşturur. Bu uzantı hücreyi ileri iter."},{"t":"Tutunma","a":"Yapışma noktaları","d":"Hücre ön kenarda zemine tutunma noktaları kurar. Bu tutunmalar hücrenin ilerlerken kuvvet uygulamasına olanak verir."},{"t":"Çekilme","a":"Arka uç toparlanır","d":"Arka uçtaki aktin-miyozin kasılması hücre gövdesini öne çeker ve eski tutunmalar çözülür. Bu döngünün tekrarı hücreyi yara yüzeyine doğru ilerletir."}],"ans":"Ön kenarda aktin polimerizasyonuyla uzantı oluşur, tutunma ve arka uçta kasılmayla hücre öne göç eder"},{"q":"Tau proteininin mikrotübülleri kararlı tutma işlevi bozulduğunda (örneğin Alzheimer) sinir hücresinde ne tür bir sorun beklenir?","steps":[{"t":"Tau proteininin işlevi","a":"Mikrotübülü stabilize eder","d":"Tau, nöron aksonlarındaki mikrotübüllere bağlanarak onları kararlı ve düzenli tutan bir proteindir. Bu mikrotübüller akson içi taşımanın raylarıdır."},{"t":"İşlev bozulması","a":"Mikrotübül dağılır","d":"Tau anormal şekilde değişip (örneğin aşırı fosforlanıp) mikrotübülden ayrılınca, mikrotübüller kararsızlaşır ve dağılabilir. Ayrılan tau yumaklar oluşturur."},{"t":"Sonuç","a":"Akson taşıması bozulur","d":"Raylar bozulduğu için besin ve sinyal moleküllerinin akson boyunca taşınması aksar. Bu, nöron işlevinin bozulmasına ve hücre ölümüne katkıda bulunur."}],"ans":"Mikrotübüller kararsızlaşır, akson içi taşıma bozulur ve nöron işlevi zarar görür"},{"q":"Bitki hücrelerinde kortikal mikrotübüllerin hücre çeperi (selüloz) dizilimini nasıl yönlendirdiğini ve bunun hücre büyümesine etkisini açıklayınız.","steps":[{"t":"Kortikal mikrotübüller","a":"Zar altında dizilir","d":"Bitki hücrelerinde hücre zarının iç yüzeyine paralel uzanan kortikal mikrotübüller bulunur. Bunlar belirli bir yönde düzenli biçimde dizilir."},{"t":"Selüloz yönlendirmesi","a":"Sentaz hareketini kılavuzlar","d":"Zardaki selüloz sentaz enzimleri kortikal mikrotübüller boyunca hareket ederek selüloz liflerini aynı yönde döşer. Böylece çeper lifleri mikrotübüllere paralel uzanır."},{"t":"Büyüme yönü","a":"Uzama yönünü belirler","d":"Selüloz lifleri hücrenin hangi yönde uzayacağını sınırlar; lifler enine ise hücre boyuna uzar. Böylece mikrotübül dizilimi hücre büyüme yönünü dolaylı olarak belirler."}],"ans":"Kortikal mikrotübüller selüloz sentazı kılavuzlayarak çeper lifi yönünü, dolayısıyla hücrenin uzama yönünü belirler"},{"q":"Mitoz iğinde kinetokor mikrotübülleri ile kutupsal (polar) mikrotübüllerin görevlerini karşılaştırınız.","steps":[{"t":"Kinetokor mikrotübülleri","a":"Kromozoma tutunur","d":"Bu mikrotübüller bir uçlarıyla kromozomların sentromerindeki kinetokora bağlanır. Anafazda kısalarak kromozomları kutuplara çeker."},{"t":"Kutupsal mikrotübüller","a":"Karşı kutuptan gelir","d":"Kutupsal mikrotübüller zıt kutuplardan uzanır ve hücrenin ortasında birbiriyle örtüşür. Kromozomlara doğrudan bağlanmazlar."},{"t":"Görev farkı","a":"Çekme vs itme","d":"Kinetokor mikrotübülleri kromozomları ayırırken, kutupsal mikrotübüller birbiri üzerinde kayarak kutupları birbirinden uzaklaştırır ve hücreyi uzatır. İkisi birlikte düzenli kromozom ayrımını sağlar."}],"ans":"Kinetokor mikrotübülleri kromozomları kutuplara çeker; kutupsal mikrotübüller kutupları uzaklaştırarak hücreyi uzatır"},{"q":"Akıcı mozaik bir hücrede hücre korteksindeki aktin ağının zayıflaması, hücre yüzeyi ve dayanıklılığı açısından hangi sonuçlara yol açar?","steps":[{"t":"Korteksin normal işlevi","a":"Yüzeyi destekler","d":"Hücre zarının altındaki aktin korteksi yüzeye mekanik dayanıklılık verir ve hücre şeklini korur. Ayrıca yüzey gerilimini ve zar uzantılarını düzenler."},{"t":"Ağın zayıflaması","a":"Destek azalır","d":"Aktin ağı zayıfladığında hücre yüzeyi destekten yoksun kalır. Zar daha gevşek ve şekilsiz hale gelir."},{"t":"Sonuç","a":"Şekil bozulur, dayanıklılık düşer","d":"Hücre mekanik strese karşı daha kırılgan olur ve şeklini koruyamaz. Yüzey uzantıları oluşturma ve hareket yeteneği de bozulur."}],"ans":"Hücre yüzeyi desteksiz kalır, şeklini koruyamaz ve mekanik dayanıklılığı azalır"},{"q":"Bir bilim insanı hücreye gama-tübulini engelleyen bir madde uyguluyor; mikrotübül oluşumunda ne tür bir bozukluk beklenir? Açıklayınız.","steps":[{"t":"Gama-tübulinin rolü","a":"Nukleasyon çekirdeği","d":"Gama-tübulin, sentrozomdaki halkalı yapılarda bulunur ve mikrotübül oluşumunun başladığı çekirdek (nukleasyon noktası) görevi görür. Yeni mikrotübüllerin eksi ucu bu halkadan başlar."},{"t":"Engellemenin etkisi","a":"Başlatma bozulur","d":"Gama-tübulin engellenirse mikrotübüllerin düzenli biçimde başlatılması (nukleasyonu) aksar. Alfa-beta tübulin var olsa bile organize bir başlangıç noktası kalmaz."},{"t":"Sonuç","a":"Düzensiz iskelet ve iğ","d":"Mikrotübül ağı düzensizleşir ve hücre bölünmesinde iki kutuplu iğ aygıtının kurulması bozulur. Bu da hücre şekli ve bölünmesini olumsuz etkiler."}],"ans":"Mikrotübül nukleasyonu (başlatma) bozulur; düzensiz iskelet ve kusurlu iğ aygıtı oluşur"},{"q":"Bir hücrede mikrotübüller, mikrofilamentler ve ara filamentler aynı anda yıkıldığında hücrenin karşılaşacağı dört temel sorunu ilişkilendirerek açıklayınız.","steps":[{"t":"Şekil ve destek kaybı","a":"Hücre dağılır","d":"Üç filament tipi de hücreye şekil ve mekanik destek verir; özellikle ara filamentler gerilmeye karşı dayanıklılık sağlar. Hepsi yıkılınca hücre belirgin şeklini ve mekanik direncini kaybeder."},{"t":"Taşıma ve organel konumu","a":"İç düzen bozulur","d":"Mikrotübüller organelleri konumlandırır ve taşıma yolları oluşturur. Yıkıldıklarında organeller dağınık kalır ve hücre içi taşıma durur."},{"t":"Hareket kaybı","a":"Hücre hareket edemez","d":"Aktin yalancı ayak ve göç hareketini, mikrotübüller ise sil-kamçı hareketini sağlar. Bunların kaybı hücreyi hareketsiz bırakır."},{"t":"Bölünme bozukluğu","a":"Mitoz ve sitokinez aksar","d":"Mikrotübül iğ ipliklerini, aktin ise sitokinez halkasını oluşturur. İkisinin de yokluğu kromozom ayrımını ve sitoplazma bölünmesini engeller."}],"ans":"Hücre şekil/desteğini, organel taşımasını, hareketini ve bölünme yeteneğini birden kaybeder"}]}},"hucreZari":{"ilkokul":{"kolay":[{"q":"Hücrenin etrafını saran ve içini dışarıdan ayıran ince örtüye ne ad verilir?","steps":[{"t":"Hücrenin dışı","a":"Bir örtü var","d":"Hücrenin içini koruyan ve onu çevresinden ayıran ince bir tabaka bulunur. Bu tabaka hücrenin sınırını belirler."},{"t":"Örtünün adı","a":"Hücre zarı","d":"Bu ince örtüye hücre zarı denir. Hücrenin içeriğini bir arada tutar ve dış ortamdan ayırır."}],"ans":"Hücre zarı"},{"q":"Hücre zarı her maddeyi içeri alır mı, yoksa seçim yapar mı?","steps":[{"t":"Zarın görevi","a":"Geçişi kontrol eder","d":"Hücre zarı, hangi maddenin gireceğine ve çıkacağına karar veren bir kapı gibidir. Her maddeyi serbestçe geçirmez."},{"t":"Seçim yapma","a":"Seçici geçirgendir","d":"Zar bazı maddeleri geçirir, bazılarını geçirmez; buna seçici geçirgenlik denir. Böylece hücre kendine yararlı maddeleri içeride tutar."}],"ans":"Seçim yapar; seçici geçirgendir"},{"q":"Hücre zarının başlıca iki görevi nedir?","steps":[{"t":"Birinci görev","a":"Koruma ve sınır","d":"Hücre zarı hücrenin içeriğini sarar ve dış ortamdan ayırır. Böylece hücreyi korur ve bir arada tutar."},{"t":"İkinci görev","a":"Madde geçişi","d":"Zar hücreye giren ve çıkan maddeleri denetler. İhtiyaç duyulan maddeleri alır, zararlı veya gereksiz olanları dışarıda tutar."}],"ans":"Hücreyi korumak ve madde giriş çıkışını kontrol etmek"},{"q":"Şeker su içinde eridikten sonra suyun her yerine yayılır. Bu yayılma olayına benzer şekilde maddelerin hücre içinde dağılmasına ne denir?","steps":[{"t":"Yayılma gözlemi","a":"Madde dağılır","d":"Bir madde çok olduğu yerden az olduğu yere doğru kendiliğinden yayılır. Şekerin suda her yere dağılması buna örnektir."},{"t":"Olayın adı","a":"Difüzyon","d":"Maddelerin çok olduğu yerden az olduğu yere yayılmasına difüzyon denir. Bu olay enerji harcamadan kendiliğinden gerçekleşir."}],"ans":"Difüzyon"},{"q":"Suyun, az olduğu taraftan çok olduğu tarafa zar üzerinden geçmesine ne ad verilir?","steps":[{"t":"Suyun hareketi","a":"Su zardan geçer","d":"Su molekülleri hücre zarından geçebilir. Su, kendi yoğunluğunun fazla olduğu taraftan az olduğu tarafa doğru geçer."},{"t":"Olayın adı","a":"Ozmoz","d":"Suyun bir zar üzerinden bu şekilde geçmesine ozmoz denir. Ozmoz aslında suyun bir tür difüzyonudur."}],"ans":"Ozmoz"}],"zor":[{"q":"Difüzyon ve aktif taşıma arasındaki en önemli fark nedir?","steps":[{"t":"Difüzyon","a":"Enerji gerekmez","d":"Difüzyonda maddeler çoktan aza doğru kendiliğinden yayılır. Bu olay için hücre enerji harcamaz."},{"t":"Aktif taşıma","a":"Enerji gerekir","d":"Aktif taşımada maddeler azdan çoğa doğru, akışın tersine taşınır. Bu iş için hücre enerji (ATP) harcar."}],"ans":"Difüzyon enerji gerektirmez; aktif taşıma enerji harcar"},{"q":"Bir hücreyi çok tuzlu suya koyarsak hücre içindeki su ne tarafa hareket eder?","steps":[{"t":"Su yoğunluğu","a":"Dışarıda su az","d":"Çok tuzlu suda çözünmüş madde fazla, su oranı azdır. Hücrenin içinde ise su oranı dışarıya göre daha fazladır."},{"t":"Suyun yönü","a":"Dışarı çıkar","d":"Su, çok olduğu hücre içinden az olduğu dış ortama doğru geçer. Böylece hücre su kaybeder ve büzülür."}],"ans":"Su hücre içinden dışarıya çıkar"},{"q":"Hücre büyük bir besin parçasını içine alırken zarın yaptığı işleme ne ad verilir?","steps":[{"t":"Büyük parça sorunu","a":"Zardan geçemez","d":"Çok büyük besin parçaları hücre zarından doğrudan geçemez. Bu yüzden hücre farklı bir yöntem kullanır."},{"t":"Zarın çözümü","a":"Sararak alır","d":"Hücre zarı büyük parçanın etrafını sarar ve bir kese oluşturarak onu içeri alır. Bu olaya endositoz denir."}],"ans":"Endositoz"},{"q":"Hücre içinde üretilen bir maddeyi dışarı atarken kullandığı yönteme ne denir?","steps":[{"t":"Dışarı atma ihtiyacı","a":"Madde dışarı verilir","d":"Hücre bazı maddeleri üretip dışarıya salgılar. Bu maddeler küçük keseler içinde paketlenir."},{"t":"Yöntemin adı","a":"Ekzositoz","d":"Kese hücre zarıyla birleşir ve içeriğini dışarı boşaltır. Bu olaya ekzositoz denir."}],"ans":"Ekzositoz"},{"q":"Bir bitki hücresini saf suya koyduğumuzda hücre neden şişer ama patlamaz?","steps":[{"t":"Su girişi","a":"Su içeri girer","d":"Saf suda su oranı hücre içinden fazladır, bu yüzden su ozmozla hücreye girer. Hücre suyla dolup şişmeye başlar."},{"t":"Çeperin koruması","a":"Hücre çeperi tutar","d":"Bitki hücresinin zarının dışında sağlam bir hücre çeperi vardır. Bu çeper hücre içeriğini sıkıca tutarak hücrenin patlamasını engeller."}],"ans":"Hücre çeperi şişmeyi sınırladığı için hücre patlamaz, sadece gerginleşir (turgor)"}]},"ortaokul":{"kolay":[{"q":"Hücre zarının temel yapısını oluşturan ve çift sıra halinde dizilen yağ benzeri moleküller nelerdir?","steps":[{"t":"Zarın yapı taşı","a":"Yağ benzeri molekül","d":"Hücre zarı temel olarak yağa benzer özel moleküllerden oluşur. Bu moleküller suyu seven ve sevmeyen kısımlara sahiptir."},{"t":"Dizilimi","a":"Çift tabaka","d":"Bu moleküller iki sıra halinde dizilerek bir çift tabaka oluşturur; bunlara fosfolipit denir. Bu çift tabaka hücre zarının iskeletini meydana getirir."}],"ans":"Fosfolipitler (fosfolipit çift tabakası)"},{"q":"Hücre zarının fosfolipit tabakası içine gömülü olan ve madde geçişinde görev alan büyük moleküller nelerdir?","steps":[{"t":"Tabaka içindeki yapılar","a":"Gömülü moleküller","d":"Fosfolipit çift tabakasının içinde ve yüzeyinde başka büyük moleküller bulunur. Bunlar tabaka boyunca dağılmış durumdadır."},{"t":"Adları ve görevi","a":"Proteinler","d":"Bu moleküllere zar proteinleri denir ve bazı maddelerin zardan geçmesini sağlar. Ayrıca sinyal alma gibi görevleri de vardır."}],"ans":"Proteinler (zar proteinleri)"},{"q":"Hücre zarının yapısını ve hareketliliğini anlatan modelin adı nedir?","steps":[{"t":"Modelin özelliği","a":"Hareketli ve karışık","d":"Hücre zarındaki moleküller sabit değildir; fosfolipitler ve proteinler kayarak yer değiştirebilir. Bu nedenle zar akıcı kabul edilir."},{"t":"Modelin adı","a":"Akıcı mozaik model","d":"Proteinlerin tabaka içinde mozaik gibi dağılmış olması ve yapının akıcı olması nedeniyle bu modele akıcı mozaik model denir. Bu model zarın esnek yapısını açıklar."}],"ans":"Akıcı mozaik model"},{"q":"Difüzyon, ozmoz ve kolaylaştırılmış difüzyon ortak olarak hangi taşıma grubuna girer?","steps":[{"t":"Enerji durumu","a":"Enerji gerekmez","d":"Difüzyon, ozmoz ve kolaylaştırılmış difüzyonda maddeler çoktan aza doğru hareket eder. Bu hareketler için hücre enerji harcamaz."},{"t":"Grubun adı","a":"Pasif taşıma","d":"Enerji gerektirmeden, yoğunluk farkı yönünde gerçekleşen taşımalara pasif taşıma denir. Bu üç olay da pasif taşıma grubundadır."}],"ans":"Pasif taşıma"},{"q":"Kolaylaştırılmış difüzyonu basit difüzyondan ayıran temel özellik nedir?","steps":[{"t":"Basit difüzyon","a":"Doğrudan geçer","d":"Basit difüzyonda küçük moleküller doğrudan fosfolipit tabakasından geçer. Bu geçiş için yardımcıya ihtiyaç yoktur."},{"t":"Kolaylaştırılmış difüzyon","a":"Protein yardımı","d":"Kolaylaştırılmış difüzyonda madde, zardaki taşıyıcı veya kanal proteinleri aracılığıyla geçer. Yine çoktan aza doğru ve enerjisiz gerçekleşir ama protein gereklidir."}],"ans":"Kolaylaştırılmış difüzyon zar proteinleri aracılığıyla gerçekleşir"}],"zor":[{"q":"Bir hücre, glikozu kanda az, hücre içinde çok olmasına rağmen hücre içine almak istiyor. Hangi taşıma türünü kullanmak zorundadır ve neden?","steps":[{"t":"Yoğunluk yönü","a":"Azdan çoğa","d":"Glikoz dışarıda az, içeride çok olduğu için maddenin doğal akış yönü dışarıya doğrudur. Hücre ise tam tersine onu içeri almak istemektedir."},{"t":"Gereken taşıma","a":"Aktif taşıma","d":"Akışın tersine, azdan çoğa taşıma yalnızca enerji harcanarak yapılabilir. Bu nedenle hücre ATP enerjisi kullanan aktif taşımaya başvurmak zorundadır."}],"ans":"Aktif taşıma; çünkü madde yoğunluğun tersine (azdan çoğa) taşınmalı ve bu enerji gerektirir"},{"q":"Bir alyuvarı (kırmızı kan hücresi) saf suya koyarsak ne olur ve bu olaya ne ad verilir?","steps":[{"t":"Su girişi","a":"Su içeri girer","d":"Saf suda su oranı alyuvarın içinden fazladır, bu yüzden su ozmozla hücreye girer. Alyuvarın bitki gibi hücre çeperi olmadığından şişmeyi sınırlayacak yapı yoktur."},{"t":"Sonuç","a":"Hücre patlar","d":"Su girişi sürdükçe alyuvar aşırı şişer ve sonunda zarı yırtılarak patlar. Alyuvarın bu şekilde patlamasına hemoliz denir."}],"ans":"Aşırı su alıp şişer ve patlar; bu olaya hemoliz denir"},{"q":"Bir bitki hücresini çok tuzlu (yoğun) bir çözeltiye koyduğumuzda hücrede gözlenen büzülme olayına ne ad verilir?","steps":[{"t":"Su çıkışı","a":"Su dışarı gider","d":"Yoğun çözeltide su oranı hücre içinden azdır, bu yüzden su ozmozla hücreyi terk eder. Hücre su kaybederek büzülmeye başlar."},{"t":"Sonuç","a":"Plazmoliz","d":"Su kaybeden sitoplazma büzülür ve hücre zarı çeperden ayrılır. Bitki hücresindeki bu büzülme olayına plazmoliz denir."}],"ans":"Plazmoliz"},{"q":"Bir bitki hücresinin suyla dolup gerginleşmesine ve dik durmasına yardımcı olan duruma ne ad verilir?","steps":[{"t":"Su alımı","a":"Hücre su alır","d":"Bitki hücresi bol su bulunan bir ortamda ozmozla su alır ve içi suyla dolar. Su özellikle koful içinde birikir."},{"t":"Çepere basınç","a":"İçten basınç","d":"Suyla dolan hücre içeriden çepere doğru basınç uygular ve hücre gerginleşir. Bu gerginlik basıncına turgor denir ve bitkinin dik durmasını sağlar."}],"ans":"Turgor (turgor basıncı)"},{"q":"Akciğer hücrelerinde oksijenin kandan hücre içine geçmesi hangi taşıma türüyle olur? Açıklayınız.","steps":[{"t":"Oksijen yoğunluğu","a":"Çoktan aza","d":"Solunan havadaki oksijen, hücre içine göre daha yoğundur; çünkü hücre oksijeni sürekli kullanır. Bu nedenle oksijen çok olduğu dış ortamdan az olduğu hücre içine doğru hareket eder."},{"t":"Geçiş türü","a":"Difüzyon","d":"Oksijen küçük bir moleküldür ve fosfolipit tabakasından doğrudan, enerji harcanmadan geçebilir. Bu, yoğunluk farkıyla gerçekleşen basit difüzyondur."}],"ans":"Basit difüzyon; oksijen yoğun olduğu yerden az olduğu yere enerji harcanmadan geçer"}]},"lise":{"kolay":[{"q":"Fosfolipit molekülünün hidrofilik (su seven) baş ve hidrofobik (su sevmeyen) kuyruk kısımları zarda nasıl konumlanır?","steps":[{"t":"Fosfolipit yapısı","a":"Baş ve kuyruk","d":"Fosfolipit molekülünün bir ucu suyu seven (hidrofilik) fosfat başı, diğer ucu suyu sevmeyen (hidrofobik) yağ asidi kuyruklarıdır. Bu çift karakter zarın dizilimini belirler."},{"t":"Diziliş","a":"Başlar dışa, kuyruklar içe","d":"Su seven başlar hem hücre içine hem dışına, yani sulu ortamlara döner. Su sevmeyen kuyruklar ise birbirine dönerek tabakanın iç kısmında saklanır."}],"ans":"Hidrofilik başlar dış ve iç sulu ortama, hidrofobik kuyruklar tabakanın içine bakar"},{"q":"Akıcı mozaik modelde hücre zarının akıcılığını ve hayvan hücrelerinde bu akıcılığı düzenleyen molekülü açıklayınız.","steps":[{"t":"Akıcılık","a":"Moleküller hareketli","d":"Akıcı mozaik modelde fosfolipitler ve proteinler tabaka içinde yanlara doğru kayabilir. Bu hareketlilik zara akıcı bir yapı kazandırır."},{"t":"Düzenleyici molekül","a":"Kolesterol","d":"Hayvan hücrelerinin zarında bulunan kolesterol, fosfolipitler arasına yerleşerek akıcılığı dengeler. Sıcaklık değişimlerinde zarın ne çok katı ne çok gevşek olmasını sağlar."}],"ans":"Moleküllerin yanal hareketi akıcılığı sağlar; hayvan zarında kolesterol akıcılığı düzenler"},{"q":"Pasif taşımanın üç çeşidini sayıp her birini bir cümleyle tanımlayınız.","steps":[{"t":"Difüzyon ve ozmoz","a":"Doğrudan geçiş","d":"Difüzyon, maddenin çoktan aza doğru fosfolipit tabakasından doğrudan geçmesidir. Ozmoz ise suyun yarı geçirgen zardan az su olan tarafa doğru geçmesidir."},{"t":"Kolaylaştırılmış difüzyon","a":"Protein aracılı","d":"Kolaylaştırılmış difüzyon, yine çoktan aza doğru ancak taşıyıcı veya kanal proteinleri aracılığıyla yapılan geçiştir. Üçü de enerji harcamadan gerçekleşir."}],"ans":"Difüzyon, ozmoz ve kolaylaştırılmış difüzyon (hepsi enerjisiz, yoğunluk yönünde)"},{"q":"Aktif taşımayı pasif taşımadan ayıran iki temel özellik nedir?","steps":[{"t":"Yön farkı","a":"Yoğunluğun tersine","d":"Pasif taşıma çoktan aza doğru gerçekleşirken, aktif taşıma azdan çoğa, yani yoğunluk farkının tersine yapılır. Bu, maddenin akışına karşı taşımadır."},{"t":"Enerji farkı","a":"ATP gerektirir","d":"Pasif taşıma enerji gerektirmezken, aktif taşıma için hücre ATP enerjisi harcar. Taşıma taşıyıcı proteinler aracılığıyla yapılır."}],"ans":"Aktif taşıma yoğunluğun tersine yapılır ve ATP enerjisi harcar"},{"q":"Sodyum-potasyum pompası bir aktif taşıma örneğidir. Bu pompanın hangi iyonları hangi yönde taşıdığını belirtiniz.","steps":[{"t":"Sodyum yönü","a":"Sodyum dışarı","d":"Sodyum-potasyum pompası, hücre içindeki sodyum iyonlarını hücre dışına atar. Bu, sodyumun zaten az olduğu dışarıya, yani yoğunluk tersine taşımadır."},{"t":"Potasyum yönü","a":"Potasyum içeri","d":"Aynı pompa potasyum iyonlarını hücre içine alır. Her iki taşıma da yoğunluk farkının tersine olduğu için ATP enerjisi harcanır."}],"ans":"Sodyumu hücre dışına, potasyumu hücre içine taşır (ATP harcayarak)"},{"q":"Hücrenin büyük parçacıkları içeri aldığı endositozun iki tipi olan fagositoz ve pinositozu açıklayınız.","steps":[{"t":"Fagositoz","a":"Katı parça alımı","d":"Fagositoz, hücrenin büyük katı parçacıkları (örneğin bakteri) zarıyla sararak içeri almasıdır. Buna hücre yemesi de denir."},{"t":"Pinositoz","a":"Sıvı alımı","d":"Pinositoz, hücrenin sıvı damlacıklarını ve içinde çözünmüş maddeleri keseyle içeri almasıdır. Buna hücre içmesi de denir."}],"ans":"Fagositoz katı parçacık alımı (hücre yemesi), pinositoz sıvı alımıdır (hücre içmesi)"},{"q":"Bir çözelti hücreye göre hipertonik, hipotonik veya izotonik olabilir. Bu üç terimi tanımlayınız.","steps":[{"t":"Hipertonik ve hipotonik","a":"Yoğun ve seyreltik","d":"Hipertonik çözeltide çözünmüş madde hücre içinden daha fazladır, dolayısıyla su daha azdır. Hipotonik çözeltide ise çözünmüş madde hücre içinden azdır, su daha çoktur."},{"t":"İzotonik","a":"Eşit yoğunluk","d":"İzotonik çözeltide çözünmüş madde yoğunluğu hücre içiyle aynıdır. Bu durumda net su giriş çıkışı olmaz."}],"ans":"Hipertonik daha yoğun, hipotonik daha seyreltik, izotonik hücreyle eşit yoğunluktadır"},{"q":"Bir alyuvar hipertonik, izotonik ve hipotonik ortamlarda sırasıyla nasıl davranır?","steps":[{"t":"Hipertonik ortam","a":"Büzülür","d":"Hipertonik ortamda su hücreden dışarı çıkar, çünkü dışarıda su azdır. Alyuvar su kaybedip büzülür (krenasyon)."},{"t":"İzotonik ortam","a":"Değişmez","d":"İzotonik ortamda su giriş ve çıkışı eşittir. Alyuvar normal şeklini korur."},{"t":"Hipotonik ortam","a":"Şişer/patlar","d":"Hipotonik ortamda su hücreye girer ve alyuvar şişer. Aşırı su girişinde patlar (hemoliz)."}],"ans":"Hipertonikte büzülür, izotonikte değişmez, hipotonikte şişer/patlar (hemoliz)"},{"q":"Bitki hücresinde turgor ve plazmoliz durumlarını ortam yoğunluğuyla ilişkilendirerek açıklayınız.","steps":[{"t":"Turgor","a":"Hipotonik ortam","d":"Hipotonik ortamda su hücreye girer ve koful şişerek çepere basınç uygular. Bu gergin, dolgun duruma turgor denir ve bitki dik durur."},{"t":"Plazmoliz","a":"Hipertonik ortam","d":"Hipertonik ortamda su hücreden çıkar ve sitoplazma büzülerek zar çeperden ayrılır. Bu büzülme durumuna plazmoliz denir ve bitki solgunlaşır."}],"ans":"Hipotonik ortamda turgor (şişkin), hipertonik ortamda plazmoliz (büzülme) görülür"},{"q":"Hücre zarındaki kanal proteinleri ile taşıyıcı (pompa) proteinler arasındaki çalışma farkı nedir?","steps":[{"t":"Kanal proteinleri","a":"Açık geçit","d":"Kanal proteinleri zarda bir geçit oluşturur ve belirli iyon veya moleküllerin hızla geçmesine izin verir. Genellikle pasif taşımada görev alırlar."},{"t":"Taşıyıcı proteinler","a":"Şekil değiştirir","d":"Taşıyıcı proteinler maddeyi bağlar ve şekil değiştirerek karşı tarafa geçirir. Hem pasif hem de ATP kullanan aktif taşımada görev alabilirler."}],"ans":"Kanallar açık bir geçit oluşturur; taşıyıcılar maddeyi bağlayıp şekil değiştirerek taşır"},{"q":"Ekzositoz olayının basamaklarını ve hücredeki önemini açıklayınız.","steps":[{"t":"Vezikül oluşumu","a":"Madde paketlenir","d":"Hücre içinde salgılanacak maddeler (örneğin enzim, hormon) golgiden ayrılan keseciklerde (vezikül) paketlenir. Bu vezikül hücre zarına doğru ilerler."},{"t":"Zarla birleşme","a":"İçerik dışarı","d":"Vezikül hücre zarıyla kaynaşır ve içeriğini hücre dışına boşaltır. Böylece madde hücreden dışarı verilmiş olur."}],"ans":"Vezikül zarla birleşip içeriğini dışarı boşaltır; salgı ve atık maddelerin atılmasını sağlar"},{"q":"Difüzyon hızını etkileyen üç faktörü belirtip kısaca açıklayınız.","steps":[{"t":"Yoğunluk farkı ve sıcaklık","a":"Artarsa hızlanır","d":"İki taraf arasındaki yoğunluk farkı arttıkça difüzyon hızlanır. Ayrıca sıcaklık arttığında moleküller daha hızlı hareket eder ve difüzyon hızı artar."},{"t":"Molekül büyüklüğü ve yüzey","a":"Boyut ve alan","d":"Küçük moleküller büyük moleküllere göre daha hızlı difüzlenir. Geçişin gerçekleştiği yüzey alanı büyüdükçe de difüzyon hızı artar."}],"ans":"Yoğunluk farkı, sıcaklık, molekül büyüklüğü (ve yüzey alanı) difüzyon hızını etkiler"},{"q":"Hücre zarının seçici geçirgenliği ne demektir ve hangi tür maddeler fosfolipit tabakadan kolay geçer?","steps":[{"t":"Seçici geçirgenlik","a":"Geçişi denetler","d":"Seçici geçirgenlik, zarın bazı maddeleri geçirip bazılarını geçirmemesi özelliğidir. Bu sayede hücre iç ortamının dengesini korur."},{"t":"Kolay geçen maddeler","a":"Küçük ve yağda çözünen","d":"Oksijen, karbondioksit gibi küçük ve yüksüz moleküller ile yağda çözünen maddeler fosfolipit tabakadan kolayca geçer. İyonlar ve büyük polar moleküller ise protein yardımına ihtiyaç duyar."}],"ans":"Zarın maddeleri seçerek geçirmesidir; küçük, yüksüz ve yağda çözünen maddeler kolay geçer"},{"q":"Glikozun bağırsak hücresine alınmasında kolaylaştırılmış difüzyonun rolünü açıklayınız.","steps":[{"t":"Glikozun özelliği","a":"Polar molekül","d":"Glikoz büyükçe ve polar bir moleküldür, bu yüzden fosfolipit tabakadan doğrudan kolay geçemez. Geçmesi için bir yardımcı gereklidir."},{"t":"Taşıyıcı protein","a":"Çoktan aza taşır","d":"Glikoz, zardaki taşıyıcı proteinler aracılığıyla yoğun olduğu taraftan az olduğu tarafa geçer. Bu, protein gerektiren ama enerji harcamayan kolaylaştırılmış difüzyondur."}],"ans":"Glikoz, taşıyıcı protein aracılığıyla çoktan aza, enerjisiz taşınır (kolaylaştırılmış difüzyon)"},{"q":"Endositoz ve ekzositozun aktif olaylar (enerji gerektiren) sayılmasının nedeni nedir?","steps":[{"t":"Olayların doğası","a":"Zar yeniden şekillenir","d":"Endositoz ve ekzositozda hücre zarı kese oluşturmak veya keseyle birleşmek için yeniden şekillenir. Bu yapısal değişiklik kendiliğinden olmaz."},{"t":"Enerji ihtiyacı","a":"ATP harcanır","d":"Vezikül oluşturma, taşıma ve zarla birleştirme işlemleri ATP enerjisi gerektirir. Bu nedenle her iki olay da aktif (enerjili) taşıma kabul edilir."}],"ans":"Zarın kese oluşturup şekil değiştirmesi ATP enerjisi gerektirdiği için aktiftirler"}],"zor":[{"q":"Bir bilim insanı, yüksek sodyum içeren bir hücreyi soğutarak ATP üretimini durduruyor; bir süre sonra hücre içi sodyum derişiminin arttığını gözlemliyor. Bu sonucu açıklayınız.","steps":[{"t":"Normal durum","a":"Pompa sodyumu atar","d":"Normalde sodyum-potasyum pompası ATP harcayarak hücre içindeki sodyumu sürekli dışarı atar. Böylece hücre içi sodyum düşük tutulur."},{"t":"ATP kaybı","a":"Pompa durur","d":"ATP üretimi durunca aktif taşıma yapan pompa enerjisiz kalır ve çalışamaz. Sodyumu dışarı atan mekanizma devre dışı kalır."},{"t":"Sonuç","a":"Sodyum içeri sızar","d":"Pompa durduğunda sodyum, yoğunluk farkı nedeniyle pasif olarak hücre içine sızmaya devam eder. Dışarı atılamadığı için hücre içi sodyum derişimi artar."}],"ans":"ATP olmadan pompa çalışmaz, sodyum dışarı atılamaz ve pasif sızmayla hücre içinde birikir"},{"q":"İki çözelti arasındaki suyun ozmotik hareketini durdurmak için uygulanması gereken basınca osmotik basınç denir. Hipertonik çözeltinin osmotik basıncı neden yüksektir? Açıklayınız.","steps":[{"t":"Hipertonik özelliği","a":"Çok çözünmüş madde","d":"Hipertonik çözeltide çözünmüş madde derişimi yüksek, serbest su oranı düşüktür. Bu nedenle su, hipertonik tarafa doğru güçlü biçimde çekilir."},{"t":"Su çekme eğilimi","a":"Güçlü su akışı","d":"Çözünmüş madde ne kadar fazlaysa su o tarafa o kadar güçlü akmak ister. Bu güçlü akışı durdurmak için daha fazla karşı basınç gerekir."},{"t":"Sonuç","a":"Yüksek osmotik basınç","d":"Su akışını durdurmak için gereken basınç osmotik basınçtır ve madde derişimiyle doğru orantılıdır. Bu yüzden hipertonik çözeltinin osmotik basıncı yüksektir."}],"ans":"Çözünmüş madde derişimi yüksek olduğu için su çekme eğilimi güçlüdür; bu nedenle osmotik basınç yüksektir"},{"q":"Aynı şeker derişimine sahip bir hayvan hücresi ile bir bitki hücresini saf suya koyduğunuzda farklı sonuçlar gözlüyorsunuz. Bu farkın nedenini açıklayınız.","steps":[{"t":"Su girişi","a":"İkisine de su girer","d":"Saf su her iki hücreye göre hipotoniktir, bu yüzden su ozmozla iki hücreye de girer. Hücreler şişmeye başlar."},{"t":"Hayvan hücresi","a":"Patlar","d":"Hayvan hücresinin yalnızca esnek bir zarı vardır, şişmeyi sınırlayacak sert bir yapısı yoktur. Su girişi sürünce hücre patlar (hemoliz)."},{"t":"Bitki hücresi","a":"Turgora ulaşır","d":"Bitki hücresinin zarının dışında sağlam bir çeper bulunur. Çeper içe doğru karşı basınç uygulayarak su girişini sınırlar ve hücre patlamadan turgor durumuna gelir."}],"ans":"Hayvan hücresi patlar (hemoliz); bitki hücresi çeperi sayesinde patlamaz, turgora ulaşır"},{"q":"Solungaçlarıyla tatlı suda yaşayan bir balık, vücut tuzunu nasıl korur? Aktif taşımanın rolünü açıklayınız.","steps":[{"t":"Ortam farkı","a":"Dış ortam seyreltik","d":"Tatlı suda çözünmüş tuz çok azdır, balığın vücut sıvısı ise daha yoğundur. Bu nedenle su sürekli balığın vücuduna girer ve tuz dışarı sızma eğilimindedir."},{"t":"Tuz kaybı sorunu","a":"İyonlar kaçar","d":"Yoğunluk farkı nedeniyle sodyum gibi iyonlar pasif olarak vücuttan suya doğru kaybedilir. Balığın bu iyonları geri kazanması gerekir."},{"t":"Aktif taşıma","a":"İyonları geri alır","d":"Solungaç hücreleri ATP harcayarak sudaki iyonları yoğunluğun tersine vücut içine pompalar. Böylece balık aktif taşıma sayesinde tuz dengesini korur."}],"ans":"Solungaç hücreleri ATP harcayarak iyonları yoğunluğun tersine vücuda pompalar, böylece tuz kaybı telafi edilir"},{"q":"Bir hücre serum (izotonik) yerine yanlışlıkla saf su (hipotonik) ile damardan verilirse alyuvarlarda hangi tehlike oluşur? Açıklayınız.","steps":[{"t":"Saf suyun durumu","a":"Hipotonik","d":"Saf su alyuvarlara göre hipotoniktir, çünkü içinde çözünmüş madde yoktur. Bu durumda su, çoktan aza yani alyuvarın içine doğru hareket eder."},{"t":"Su girişi","a":"Alyuvar şişer","d":"Su ozmozla alyuvarın içine girer ve hücre hızla şişer. Alyuvarın çeperi olmadığından şişmeyi durduracak bir yapı yoktur."},{"t":"Sonuç","a":"Hemoliz","d":"Aşırı su girişi alyuvar zarını yırtar ve hücreler patlar; bu olaya hemoliz denir. Bu yüzden damar içi sıvılar izotonik olmak zorundadır."}],"ans":"Alyuvarlar aşırı su alıp patlar (hemoliz); bu nedenle damar içi sıvılar izotonik verilir"},{"q":"Kolesterolün hücre zarındaki akıcılık üzerine etkisinin sıcaklığa göre nasıl değiştiğini açıklayınız.","steps":[{"t":"Yüksek sıcaklık","a":"Akıcılığı azaltır","d":"Yüksek sıcaklıkta fosfolipitler aşırı hareketlenir ve zar çok akışkan, gevşek hale gelebilir. Kolesterol fosfolipit hareketini kısıtlayarak zarın aşırı akıcılaşmasını engeller."},{"t":"Düşük sıcaklık","a":"Akıcılığı artırır","d":"Düşük sıcaklıkta fosfolipitler birbirine sıkı paketlenir ve zar katılaşma eğilimine girer. Kolesterol araya girerek sıkı paketlenmeyi bozar ve zarın donup katılaşmasını önler."},{"t":"Genel rol","a":"Tampon görevi","d":"Böylece kolesterol bir tampon gibi davranır; sıcakta akıcılığı düşürür, soğukta artırır. Bu sayede zar geniş bir sıcaklık aralığında işlevsel kalır."}],"ans":"Kolesterol yüksek sıcaklıkta akıcılığı azaltır, düşük sıcaklıkta artırır; akıcılık tamponu görevi görür"},{"q":"Bir nöronun dinlenme zar potansiyelinin oluşmasında sodyum-potasyum pompası ve iyon difüzyonunun birlikte rolünü açıklayınız.","steps":[{"t":"Pompanın etkisi","a":"İyon farkı kurar","d":"Sodyum-potasyum pompası ATP harcayarak sodyumu dışarı, potasyumu içeri taşır. Bu, hücre dışında sodyumun, hücre içinde potasyumun yoğun olduğu bir gradyan oluşturur."},{"t":"Potasyum sızıntısı","a":"Potasyum dışarı kaçar","d":"Zarda potasyum sızıntı kanalları bulunur ve potasyum yoğun olduğu içeriden dışarı difüzlenir. Pozitif yüklü potasyum çıkınca hücre içi dışa göre negatif kalır."},{"t":"Sonuç","a":"Negatif iç potansiyel","d":"Pompanın kurduğu gradyan ve potasyumun difüzyonu birlikte hücre içini dışa göre yaklaşık eksi 70 milivolt negatif yapar. Bu, dinlenme zar potansiyelidir."}],"ans":"Pompa iyon gradyanını kurar, potasyumun dışa difüzyonu içeriyi negatif bırakır; birlikte dinlenme potansiyelini oluşturur"},{"q":"Bağırsak hücresinde glikozun lümenden kana taşınmasında sodyum gradyanını kullanan ikincil aktif taşımayı (kotransport) açıklayınız.","steps":[{"t":"Sodyum gradyanı","a":"Pompayla kurulur","d":"Sodyum-potasyum pompası ATP harcayarak hücredeki sodyumu dışarı atar ve hücre içi sodyumu düşük tutar. Böylece hücre dışında yüksek bir sodyum derişimi (gradyan) oluşur."},{"t":"Ortak taşıyıcı","a":"Sodyumla birlikte glikoz","d":"Lümen tarafındaki bir taşıyıcı protein, sodyum hücreye gradyanı yönünde girerken glikozu da onunla birlikte içeri çeker. Glikoz kendi yoğunluğunun tersine taşınsa da enerjiyi doğrudan ATP değil, sodyum gradyanı sağlar."},{"t":"Dolaylı enerji","a":"ATP dolaylı kullanılır","d":"Sodyum gradyanını kurmak için harcanan ATP, glikoz taşımasının dolaylı enerji kaynağıdır. Bu nedenle bu olaya ikincil (sekonder) aktif taşıma denir."}],"ans":"Pompayla kurulan sodyum gradyanı, ortak taşıyıcıyla glikozu içeri çeker; enerji dolaylı olarak ATP'den gelir (ikincil aktif taşıma)"},{"q":"Bir araştırmacı zardaki protein kanallarını bloke eden bir ilaç uyguluyor; küçük yüksüz moleküllerin (oksijen) geçişi etkilenmezken iyonların geçişi durıyor. Bu sonucu açıklayınız.","steps":[{"t":"Oksijen geçişi","a":"Protein gerekmez","d":"Oksijen küçük ve yüksüz bir moleküldür, fosfolipit tabakasından doğrudan basit difüzyonla geçer. Bu geçiş için protein kanalına ihtiyaç yoktur, bu yüzden ilaçtan etkilenmez."},{"t":"İyon geçişi","a":"Kanal gerekli","d":"İyonlar yüklü ve hidrofilik olduğundan yağ tabakasından doğrudan geçemez, mutlaka protein kanallarını kullanır. İlaç bu kanalları bloke edince iyonlar geçecek yol bulamaz."},{"t":"Sonuç","a":"Seçici etkilenme","d":"Bu durum zarın seçici geçirgenliğini ve geçiş yollarının farklılığını gösterir. Kanal bağımlı geçişler durur, fosfolipitten doğrudan geçen maddeler etkilenmez."}],"ans":"Oksijen fosfolipitten doğrudan geçtiği için etkilenmez; iyonlar kanal proteinine bağımlı olduğu için geçişleri durur"},{"q":"Bir bitki yaprağı solduğunda sulandığında tekrar dikleşiyor. Bu olayı turgor ve plazmoliz kavramlarıyla açıklayınız.","steps":[{"t":"Solma anı","a":"Su kaybı","d":"Su yetersizliğinde hücreler ozmozla su kaybeder ve kofullar küçülür. Hücreler turgorunu yitirip gevşer, bu yüzden yaprak solar ve sarkar."},{"t":"Aşırı su kaybı","a":"Plazmoliz riski","d":"Su kaybı arttıkça sitoplazma daha da büzülür ve şiddetli durumda zar çeperden ayrılarak plazmolize yaklaşır. Bu durum yaprağın daha da pörsümesine yol açar."},{"t":"Sulama sonrası","a":"Turgor geri gelir","d":"Bitki sulandığında hücreler ozmozla yeniden su alır ve kofullar şişer. Çepere uygulanan turgor basıncı artınca hücreler dikleşir ve yaprak tekrar gerginleşir."}],"ans":"Su kaybında turgor azalıp yaprak solar; sulanınca hücreler su alıp turgor kazanır ve yaprak dikleşir"},{"q":"Hücre, bir hormonu salgılarken ekzositoz, bir bakteriyi yok etmek için ise endositoz kullanır. Bu iki olayın enerji ve zar açısından zıt yönlü olduğunu açıklayınız.","steps":[{"t":"Ekzositoz","a":"Zar dışarı verilir","d":"Ekzositozda hücre içindeki vezikül hücre zarıyla birleşir ve içeriğini dışarı boşaltır. Bu sırada vezikül zarı hücre zarına eklenir, yani zar yüzeyi artar."},{"t":"Endositoz","a":"Zar içeri alınır","d":"Endositozda hücre zarı içe doğru çökerek bir kese oluşturur ve dışarıdaki maddeyi içeri alır. Bu sırada zarın bir kısmı hücre içine çekilir, yani zar yüzeyi azalır."},{"t":"Ortak nokta","a":"İkisi de ATP harcar","d":"Her iki olay da zarın yeniden şekillenmesini gerektirdiği için ATP enerjisi harcar. Yön bakımından zıt olsalar da hücre içi ve dışı arasındaki zar dengesini birlikte korurlar."}],"ans":"Ekzositoz zarı dışarı verir (madde salar), endositoz zarı içeri alır (madde alır); ikisi de ATP harcar ve zar dengesini korur"},{"q":"Bir hücre dış ortamdan bir büyüme faktörünü algılayıp tepki veriyor. Bu süreçte zar proteinlerinin (reseptör) rolünü açıklayınız.","steps":[{"t":"Sinyal molekülü","a":"Zardan geçemez","d":"Büyüme faktörü gibi birçok sinyal molekülü büyük veya polar olduğu için hücre zarından doğrudan geçemez. Bu yüzden hücre içine girmeden algılanması gerekir."},{"t":"Reseptöre bağlanma","a":"Protein algılar","d":"Zardaki reseptör proteinleri, dış ortamdaki sinyal molekülünü bağlar. Bağlanma reseptörün şeklini değiştirir."},{"t":"Hücre içi tepki","a":"Sinyal iletilir","d":"Şekil değişimi hücrenin içine doğru bir sinyal başlatır ve hücre içi olaylar zinciri tetiklenir. Böylece hücre, sinyal molekülü içeri girmeden ona tepki verir."}],"ans":"Zar reseptör proteinleri sinyali bağlar, şekil değiştirerek hücre içine ileti gönderir; molekül içeri girmeden tepki oluşur"},{"q":"Bir öğrenci, oksijen ve karbondioksitin akciğer ile doku hücreleri arasında zıt yönlerde difüzlendiğini söylüyor. Bu gazların yön farkını yoğunluk gradyanıyla açıklayınız.","steps":[{"t":"Akciğerde oksijen","a":"Kana girer","d":"Akciğer alveollerinde oksijen yoğunken kanda azdır, bu yüzden oksijen çoktan aza doğru kana difüzlenir. Aynı yerde kandaki karbondioksit yoğun olduğundan alveole geçer."},{"t":"Dokuda oksijen","a":"Hücreye girer","d":"Dokuda hücreler oksijeni sürekli tükettiği için hücre içi oksijen azdır. Kandaki oksijen yoğun olduğundan dokuya, hücre içine difüzlenir."},{"t":"Dokuda karbondioksit","a":"Kana çıkar","d":"Hücreler solunumla karbondioksit ürettiği için hücre içi karbondioksiti yoğundur. Bu yüzden karbondioksit hücreden kana difüzlenir; gazlar her yerde kendi yoğunluk gradyanını izler."}],"ans":"Her gaz çoktan aza difüzlenir: akciğerde O2 kana/CO2 alveole, dokuda O2 hücreye/CO2 kana geçer"},{"q":"Kolaylaştırılmış difüzyonda taşıyıcı proteinlerin doygunluğa ulaşması ne anlama gelir ve bu basit difüzyondan nasıl bir farktır?","steps":[{"t":"Taşıyıcı sınırı","a":"Protein sayısı sınırlı","d":"Kolaylaştırılmış difüzyon belirli sayıda taşıyıcı protein aracılığıyla yapılır. Madde derişimi arttıkça taşıma hızlanır, ancak tüm taşıyıcılar dolunca hız daha fazla artmaz."},{"t":"Doygunluk","a":"Hız sabitlenir","d":"Tüm taşıyıcıların sürekli meşgul olduğu noktaya doygunluk denir. Bu noktadan sonra derişimi artırmak taşıma hızını artırmaz, çünkü taşıyıcı kapasitesi tükenmiştir."},{"t":"Basit difüzyonla fark","a":"Basit difüzyon doygunlaşmaz","d":"Basit difüzyonda protein kullanılmadığı için bir doygunluk sınırı yoktur; derişim arttıkça hız artmaya devam eder. Doygunluk olması, kolaylaştırılmış difüzyonun protein bağımlı olduğunu gösterir."}],"ans":"Tüm taşıyıcılar dolunca taşıma hızı sabitlenir (doygunluk); basit difüzyonda protein olmadığı için doygunluk görülmez"},{"q":"Bir hücre hipertonik ortamda büzülürken, aynı ortama eklenen su yavaşça hücreyi izotonik dengeye getiriyor. Bu süreci ozmoz ve yoğunluk denkleşmesiyle açıklayınız.","steps":[{"t":"Başlangıç durumu","a":"Hipertonik ortam","d":"Başta dış ortam hücreden daha yoğundur, su hücreden dışarı çıkar ve hücre büzülür. Net su hareketi hücre içinden dışarıya doğrudur."},{"t":"Su eklenmesi","a":"Ortam seyreltilir","d":"Ortama su eklendikçe dış çözeltinin çözünmüş madde derişimi azalır. Dış ortam giderek hücre içine yaklaşan bir yoğunluğa gelir."},{"t":"Denge","a":"İzotonik durum","d":"Dış ve iç yoğunluklar eşitlendiğinde net su giriş çıkışı durur; bu izotonik dengedir. Bu noktada ozmotik su hareketi iki yönde eşit olduğundan hücrenin hacmi sabitlenir."}],"ans":"Su eklendikçe ortam seyrelir, dış-iç yoğunluk eşitlenir; izotonik dengede net su hareketi durur ve hücre hacmi sabitlenir"}]}}};
